-- Poems batch 193
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5a18d54e-de72-477f-b4bf-a16066f9a120','雜興四首  其一','蘇泂','宋','宋诗','song-poetry','','[]','滿地秋聲皷吹同，草根無頼更寒蛩。',32,'全唐诗/poet.song.184000.json','["滿地秋聲皷吹同，草根無頼更寒蛩。", "情知萬事終摇落，忍見霜林一葉紅。"]'),
('a6bfa1fc-b705-4b46-959d-d534470d592c','雜興四首  其二','蘇泂','宋','宋诗','song-poetry','','[]','秋衾薄薄換吳綾，燈焰無多一半青。',32,'全唐诗/poet.song.184000.json','["秋衾薄薄換吳綾，燈焰無多一半青。", "却憶舊時荆楚岸，夜深風雨泊船聽。"]'),
('14c61ffe-a09c-4d12-89fc-13ebc7c1efc0','雜興四首  其三','蘇泂','宋','宋诗','song-poetry','','[]','蘭佩其如楚客悲，年年誰作感秋辭。',32,'全唐诗/poet.song.184000.json','["蘭佩其如楚客悲，年年誰作感秋辭。", "不應白骨蒼苔後，更愛西風落葉時。"]'),
('95363edf-e443-405d-9b71-0d6a5f77b6f8','雜興四首  其四','蘇泂','宋','宋诗','song-poetry','','[]','琵琶亭下維舟處，水落江空夜雪殘。',32,'全唐诗/poet.song.185000.json','["琵琶亭下維舟處，水落江空夜雪殘。", "記得長官邀我醉，縣衙當面玉爲山。"]'),
('eac6fafc-6a45-4e1f-bb2a-18a534043995','次韻潁叟弟耕堂雜興六首  其一','蘇泂','宋','宋诗','song-poetry','','[]','莫求名字滿鄉閭，且讀平生萬卷書。',32,'全唐诗/poet.song.185000.json','["莫求名字滿鄉閭，且讀平生萬卷書。", "青箬笠邊無不可，黄金带後欲如何。"]'),
('87ea0447-605f-481a-a5c4-788ffa451871','次韻潁叟弟耕堂雜興六首  其二','蘇泂','宋','宋诗','song-poetry','','[]','繚繞州城带雨長，雨餘雲氣亦飛揚。',32,'全唐诗/poet.song.185000.json','["繚繞州城带雨長，雨餘雲氣亦飛揚。", "小樓別有幽欣處，時復風吹荷葉香。"]'),
('5896e6e5-141d-41c6-b051-ab4a74c765d9','次韻潁叟弟耕堂雜興六首  其三','蘇泂','宋','宋诗','song-poetry','','[]','吳蜀歸來興寄遐，天將清氣與貧家。',32,'全唐诗/poet.song.185000.json','["吳蜀歸來興寄遐，天將清氣與貧家。", "雙雙蝶舞宜男草，箇箇蜂銜附子花。"]'),
('33c10d39-108d-4db5-a800-792a8641f649','次韻潁叟弟耕堂雜興六首  其四','蘇泂','宋','宋诗','song-poetry','','[]','莫怪龐公不入城，都緣無事可牽縈。',32,'全唐诗/poet.song.185000.json','["莫怪龐公不入城，都緣無事可牽縈。", "客來遇酒飲何害，客去投床夢亦清。"]'),
('640b1e70-a962-496a-92aa-4ac8f5743f47','次韻潁叟弟耕堂雜興六首  其五','蘇泂','宋','宋诗','song-poetry','','[]','已芸何似與人芸，水旱螟蝗不可聞。',32,'全唐诗/poet.song.185000.json','["已芸何似與人芸，水旱螟蝗不可聞。", "必欲糠粞飽雞鶩，明年余作勸農文。"]'),
('e25e89a0-09d0-4f81-bfa9-1380dc66fb60','次韻潁叟弟耕堂雜興六首  其六','蘇泂','宋','宋诗','song-poetry','','[]','珍重新來十絕詩，末章砥柱不能移。',32,'全唐诗/poet.song.185000.json','["珍重新來十絕詩，末章砥柱不能移。", "因思唐代諸公子，故少撞鐘得意時。"]'),
('a91aa24b-d6ab-4ee4-a206-72ca27273612','次韻趙去華提幹夏日雜興七首  其一','蘇泂','宋','宋诗','song-poetry','','[]','老子軒冕總相忘，歸辦芙蓉製作裳。',32,'全唐诗/poet.song.185000.json','["老子軒冕總相忘，歸辦芙蓉製作裳。", "多少隠淪天下士，無人知我亦何傷。"]'),
('809e1f6a-43a8-4391-af8f-b769fc43e460','次韻趙去華提幹夏日雜興七首  其二','蘇泂','宋','宋诗','song-poetry','','[]','客醉如何我獨醒，山空時落澗泉聲。',32,'全唐诗/poet.song.185000.json','["客醉如何我獨醒，山空時落澗泉聲。", "年來不踏長安市，贏得詩書一味清。"]'),
('ab8097b0-6b01-47e3-af4a-cb8711a5796f','次韻趙去華提幹夏日雜興七首  其三','蘇泂','宋','宋诗','song-poetry','','[]','幸是安心無可病，不曾爲米底須歸。',32,'全唐诗/poet.song.185000.json','["幸是安心無可病，不曾爲米底須歸。", "養成乳鹿充神駕，散拾殘雲補道衣。"]'),
('b065523d-d224-41eb-9ae1-3443e9b7cc7c','次韻趙去華提幹夏日雜興七首  其四','蘇泂','宋','宋诗','song-poetry','','[]','植立不徒當日計，顛冥忍受一饑驅。',32,'全唐诗/poet.song.185000.json','["植立不徒當日計，顛冥忍受一饑驅。", "吟成拙賦何曾拙，喚作愚溪豈是愚。"]'),
('d9ae48e0-a123-4325-9df9-52d628734b77','次韻趙去華提幹夏日雜興七首  其五','蘇泂','宋','宋诗','song-poetry','','[]','忽然鏡裏一絲絲，老却英雄不自知。',32,'全唐诗/poet.song.185000.json','["忽然鏡裏一絲絲，老却英雄不自知。", "夜半閑來看青史，百年有盡此身危。"]'),
('515d936a-1b36-4f30-924f-9555c0c915bf','次韻趙去華提幹夏日雜興七首  其六','蘇泂','宋','宋诗','song-poetry','','[]','山外情知更有山，幾多突兀共巑岏。',32,'全唐诗/poet.song.185000.json','["山外情知更有山，幾多突兀共巑岏。", "一從夢到天壇後，轉覺丘陵不足看。"]'),
('8e5afffb-ec38-412f-bed3-20770d9faa09','次韻趙去華提幹夏日雜興七首  其七','蘇泂','宋','宋诗','song-poetry','','[]','貧甚誰傳辟穀方，閉門飲水自徜徉。',32,'全唐诗/poet.song.185000.json','["貧甚誰傳辟穀方，閉門飲水自徜徉。", "無求無欲無魔惱，月白庭空一炷香。"]'),
('edcf9f06-5a61-4362-a01a-1e8fc1a68d4a','苕溪雜興四首  其一','蘇泂','宋','宋诗','song-poetry','','[]','斜風細雨轉船頭，夜半波平带月流。',32,'全唐诗/poet.song.185000.json','["斜風細雨轉船頭，夜半波平带月流。", "行到下菰城畔望，水晶宮闕是湖州。"]'),
('20c95347-1124-436c-9697-1ea8d5b7e3e4','苕溪雜興四首  其二','蘇泂','宋','宋诗','song-poetry','','[]','美人樓上曉梳頭，人映清波波映樓。',32,'全唐诗/poet.song.185000.json','["美人樓上曉梳頭，人映清波波映樓。", "來往舟行看不足，此中風景勝揚州。"]'),
('8eb403fa-7cad-4bf2-a87b-40eb70412a7f','苕溪雜興四首  其三','蘇泂','宋','宋诗','song-poetry','','[]','只道還家猶未還，故山書冊蠹魚殘。',32,'全唐诗/poet.song.185000.json','["只道還家猶未還，故山書冊蠹魚殘。", "半生不療饑寒苦，空有詩名滿世間。"]'),
('ce0e5f85-5f56-4e03-9c99-c2962ca6dce6','苕溪雜興四首  其四','蘇泂','宋','宋诗','song-poetry','','[]','筆判虛空也太奇，古今天下幾多詩。',32,'全唐诗/poet.song.185000.json','["筆判虛空也太奇，古今天下幾多詩。", "虛空判了元無盡，信手拈來自不知。"]'),
('90492caa-7f60-4f1a-a0a8-92b9a6c45c1d','過金陵四首  其一','蘇泂','宋','宋诗','song-poetry','','[]','豆田無數老鴉飛，棗熟菰香稻子垂。',32,'全唐诗/poet.song.185000.json','["豆田無數老鴉飛，棗熟菰香稻子垂。", "未說前年那有此，今年還似去年時。"]'),
('772a8f0e-35ce-4bfe-8ec8-8b151bbad1d2','過金陵四首  其二','蘇泂','宋','宋诗','song-poetry','','[]','老樹前頭柿葉紅，又騎瘦馬立西風。',32,'全唐诗/poet.song.185000.json','["老樹前頭柿葉紅，又騎瘦馬立西風。", "江山未必儂能認，却被江山認得儂。"]'),
('30d15e67-c3a3-442b-94ec-49c15918c5ff','過金陵四首  其三','蘇泂','宋','宋诗','song-poetry','','[]','飛鴻渺渺襯蒹葭，蓼岸紅饒小穗花。',32,'全唐诗/poet.song.185000.json','["飛鴻渺渺襯蒹葭，蓼岸紅饒小穗花。", "此是秋光最佳處，江湖何處不思家。"]'),
('1e8f125d-c0df-4ae1-be44-de052479e2e2','過金陵四首  其四','蘇泂','宋','宋诗','song-poetry','','[]','高資店裏主人婆，萬福官人問訊和。',32,'全唐诗/poet.song.185000.json','["高資店裏主人婆，萬福官人問訊和。", "安穩在家能幾日，別時不似見時多。"]'),
('870c7f26-6767-4292-927b-66a1849dfd64','金陵雜興二百首  其一','蘇泂','宋','宋诗','song-poetry','','[]','玉麟堂下柳絲絲，過了春風一半時。',32,'全唐诗/poet.song.185000.json','["玉麟堂下柳絲絲，過了春風一半時。", "行到水鄉應底事，黄鶑飛上杏花枝。"]'),
('1fb8fe74-9d90-4ffb-8694-8ddf28818121','金陵雜興二百首  其二','蘇泂','宋','宋诗','song-poetry','','[]','朱雀街頭觀闕紅，角門東畔好春風。',32,'全唐诗/poet.song.185000.json','["朱雀街頭觀闕紅，角門東畔好春風。", "人家一樣垂楊柳，種入宮牆自不同。"]'),
('2ec4760f-3ec2-41b5-8a96-c1384016f1e1','金陵雜興二百首  其三','蘇泂','宋','宋诗','song-poetry','','[]','浪說思家不我聽，蕭齋閑對竹青青。',32,'全唐诗/poet.song.185000.json','["浪說思家不我聽，蕭齋閑對竹青青。", "若爲解釋妻兒念，讀盡欒城道德經。"]'),
('5a46fe23-6317-4fad-a2ec-298991bdb9c1','金陵雜興二百首  其四','蘇泂','宋','宋诗','song-poetry','','[]','桑林伐盡棗林空，賣得柴錢飯不充。',32,'全唐诗/poet.song.185000.json','["桑林伐盡棗林空，賣得柴錢飯不充。", "明日死生猶未必，將何纏裹過秋冬。"]'),
('687c3fc2-3e2e-438d-9b3e-d808ee2f545b','金陵雜興二百首  其五','蘇泂','宋','宋诗','song-poetry','','[]','江南隄柳拂人頭，三月吹花特地愁。',32,'全唐诗/poet.song.185000.json','["江南隄柳拂人頭，三月吹花特地愁。", "却憶舊時狂李白，題詩曾遍酒家樓。"]'),
('29dd3bda-a1a2-43fe-aa3d-de16aa954135','金陵雜興二百首  其六','蘇泂','宋','宋诗','song-poetry','','[]','稍經運瀆過潮溝，野草閑花觸處愁。',32,'全唐诗/poet.song.185000.json','["稍經運瀆過潮溝，野草閑花觸處愁。", "二十四航春水滿，有誰來此上扁舟。"]'),
('eee83ef9-82f7-491d-bd35-b63e146b15cd','金陵雜興二百首  其七','蘇泂','宋','宋诗','song-poetry','','[]','有時幽鳥百般啼，無數階頭萱草齊。',32,'全唐诗/poet.song.185000.json','["有時幽鳥百般啼，無數階頭萱草齊。", "第一怕聽泥滑滑，再三莫放雨凄凄。"]'),
('1db1319e-dde8-41b4-94d5-332157abbca9','金陵雜興二百首  其八','蘇泂','宋','宋诗','song-poetry','','[]','蔞蒿登盤朝飯美，河魨入市晚羹香。',32,'全唐诗/poet.song.185000.json','["蔞蒿登盤朝飯美，河魨入市晚羹香。", "應無白傅思春草，却有東坡賦海棠。"]'),
('dc88fea0-999e-468b-8441-1c95bfe8ee05','金陵雜興二百首  其九','蘇泂','宋','宋诗','song-poetry','','[]','碧煙騰上青松樹，下有仙人此煉丹。',32,'全唐诗/poet.song.185000.json','["碧煙騰上青松樹，下有仙人此煉丹。", "丹成不願千千歲，乞與前生一味閒。"]'),
('f00a36f9-3d94-4201-aee0-6f6a6c0891bc','金陵雜興二百首  其一○','蘇泂','宋','宋诗','song-poetry','','[]','歸心突兀不可制，一夜夢中行越山。',32,'全唐诗/poet.song.185000.json','["歸心突兀不可制，一夜夢中行越山。", "驚覺恍然猶是客，欲隨春色共東還。"]'),
('c7363270-6ef8-4410-81b5-df8b9c048db5','金陵雜興二百首  其一一','蘇泂','宋','宋诗','song-poetry','','[]','小小遊車四面紅，美人花貌映玲瓏。',32,'全唐诗/poet.song.185000.json','["小小遊車四面紅，美人花貌映玲瓏。", "隨車更有郎行馬，散入鍾山十里松。"]'),
('fda926ae-93c6-429f-83a6-ddb831dcb387','金陵雜興二百首  其一二','蘇泂','宋','宋诗','song-poetry','','[]','萬鑰深深待駕臨，府藏戈甲庫黄金。',32,'全唐诗/poet.song.185000.json','["萬鑰深深待駕臨，府藏戈甲庫黄金。", "規恢畫餠翻增弊，孤負先皇一片心。"]'),
('381eef47-81e9-40c8-889e-771488fbe1c8','金陵雜興二百首  其一三','蘇泂','宋','宋诗','song-poetry','','[]','永巷斜廊閙戟闈，帕黄寂寞護龍墀。',32,'全唐诗/poet.song.185000.json','["永巷斜廊閙戟闈，帕黄寂寞護龍墀。", "深宮不與閒人到，只許珍禽自在飛。"]'),
('5d144705-9087-4269-8c30-952b03e2e548','金陵雜興二百首  其一四','蘇泂','宋','宋诗','song-poetry','','[]','南位之南下曲街，畫羅窗戶隔紅梅。',32,'全唐诗/poet.song.185000.json','["南位之南下曲街，畫羅窗戶隔紅梅。", "方方丈石平如掌，曾是官家拜斗來。"]'),
('f7c9be12-7f73-41f6-8cac-5f3d5c750e92','金陵雜興二百首  其一五','蘇泂','宋','宋诗','song-poetry','','[]','小小規模似禁中，分明夏禹欲卑宮。',32,'全唐诗/poet.song.185000.json','["小小規模似禁中，分明夏禹欲卑宮。", "白頭官吏知年幾，猶指屏風說孝宗。"]'),
('7336a609-e2d2-498a-a05f-039b309712cc','金陵雜興二百首  其一六','蘇泂','宋','宋诗','song-poetry','','[]','三山摻別是前年，除夜還家翁已仙。',32,'全唐诗/poet.song.185000.json','["三山摻別是前年，除夜還家翁已仙。", "少小知憐今老矣，每因得句輒潸然。"]'),
('3f618ab8-7b5b-43b2-a5d1-4107720d76fd','金陵雜興二百首  其一七','蘇泂','宋','宋诗','song-poetry','','[]','五陵歌舞換埃塵，地下黄金出尚新。',32,'全唐诗/poet.song.185000.json','["五陵歌舞換埃塵，地下黄金出尚新。", "碑字已漫青草死，酸風吹殺石麒麟。"]'),
('d43eba21-fafc-4197-8f9f-5c8007913677','金陵雜興二百首  其一八','蘇泂','宋','宋诗','song-poetry','','[]','江風吹面雪漫漫，二月東風特地寒。',32,'全唐诗/poet.song.185000.json','["江風吹面雪漫漫，二月東風特地寒。", "四十病身誰役汝，小車摇兀過長干。"]'),
('c374ad29-caf6-4c56-9b8e-e72c55302003','金陵雜興二百首  其一九','蘇泂','宋','宋诗','song-poetry','','[]','去年夜半草軍書，今歲平安一事無。',32,'全唐诗/poet.song.185000.json','["去年夜半草軍書，今歲平安一事無。", "且願吾皇千萬壽，早教車馬會東都。"]'),
