('96e21394-63d5-4ca2-9ef5-c1b6148a2394','題金陵雜興詩後十八首  其五','李璉','宋','宋诗','song-poetry','','[]','長干小婦學吹簫，樓外閒風弄翠條。',32,'全唐诗/poet.song.185000.json','["長干小婦學吹簫，樓外閒風弄翠條。", "近得廣陵消息未，暮潮已過赤欄橋。"]'),
('8c1d5dbe-f83f-4a6d-af13-d31b0567ecb3','題金陵雜興詩後十八首  其六','李璉','宋','宋诗','song-poetry','','[]','暮雨瀟瀟郎不歸，樽前誰憶舊歌詞。',32,'全唐诗/poet.song.185000.json','["暮雨瀟瀟郎不歸，樽前誰憶舊歌詞。", "望夫烏臼濃于染，葉葉驚秋恨欲飛。"]'),
('603873e6-a579-40aa-9392-53864755d682','題金陵雜興詩後十八首  其七','李璉','宋','宋诗','song-poetry','','[]','愁看幕府夕陽邊，那更雞籠在目前。',32,'全唐诗/poet.song.185000.json','["愁看幕府夕陽邊，那更雞籠在目前。", "跋扈飛揚只如此，登高安得不酸然。"]'),
('cd883b2c-170e-4f32-85fc-390e4014f04a','題金陵雜興詩後十八首  其八','李璉','宋','宋诗','song-poetry','','[]','細竹千竿殿影斜，龍顔曾此著袈裟。',32,'全唐诗/poet.song.185000.json','["細竹千竿殿影斜，龍顔曾此著袈裟。", "寺樓杳杳鐘聲過，疑有宮娥出晚花。"]'),
('f74c56eb-8849-42dd-be1a-297049187f06','題金陵雜興詩後十八首  其九','李璉','宋','宋诗','song-poetry','','[]','池邊石是南朝石，綠染苔花亦可憐。',32,'全唐诗/poet.song.185000.json','["池邊石是南朝石，綠染苔花亦可憐。", "今日波平人事變，白魚猶自躍天泉。"]'),
('e8402b65-d93e-473f-a456-98472034e359','題金陵雜興詩後十八首  其一○','李璉','宋','宋诗','song-poetry','','[]','江水無情碧草春，北朝留住老詞臣。',32,'全唐诗/poet.song.185000.json','["江水無情碧草春，北朝留住老詞臣。", "子規啼上青楓樹，爲爾離鄉去國人。"]'),
('32a71e8d-6262-4a63-bab4-1e7114a07c70','題金陵雜興詩後十八首  其一一','李璉','宋','宋诗','song-poetry','','[]','相君息女小乘僧，身向西天佛律行。',32,'全唐诗/poet.song.185000.json','["相君息女小乘僧，身向西天佛律行。", "三尺戒壇秋色緊，箇中螻蟻亦長生。"]'),
('ca31dd27-0e6f-46c4-a4fb-706389de2d8d','題金陵雜興詩後十八首  其一二','李璉','宋','宋诗','song-poetry','','[]','夜過江左從鸞旂，從此靈君著漢衣。',32,'全唐诗/poet.song.185000.json','["夜過江左從鸞旂，從此靈君著漢衣。", "春到陰山花似雪，望鄉臺上鷓鴣飛。"]'),
('eb575c92-ffef-4450-a211-f2122cf852c3','題金陵雜興詩後十八首  其一三','李璉','宋','宋诗','song-poetry','','[]','南門點檢舊行蹤，最苦人人認得儂。',32,'全唐诗/poet.song.185000.json','["南門點檢舊行蹤，最苦人人認得儂。", "羞澁面皮無處著，橫拖山屐過青松。"]'),
('8488b3aa-3301-4488-bf50-fe8859023ad2','題金陵雜興詩後十八首  其一四','李璉','宋','宋诗','song-poetry','','[]','司馬家兒持酒杯，天星下吸亦佳哉。',32,'全唐诗/poet.song.185000.json','["司馬家兒持酒杯，天星下吸亦佳哉。", "恨渠不便傚牛飲，那得孟津師旅來。"]'),
('7731881f-a9ae-452f-a8fc-f624acc52a24','題金陵雜興詩後十八首  其一五','李璉','宋','宋诗','song-poetry','','[]','孫帝陵傍水最悲，蔣侯廟下月來遲。',32,'全唐诗/poet.song.185000.json','["孫帝陵傍水最悲，蔣侯廟下月來遲。", "夜深客子心驚恐，猿掛南朝楓樹枝。"]'),
('e67782fa-d984-4c9e-b537-8099ce215676','題金陵雜興詩後十八首  其一六','李璉','宋','宋诗','song-poetry','','[]','雲杪熒熒一塔燈，覺皇舍利寶煙凝。',32,'全唐诗/poet.song.185000.json','["雲杪熒熒一塔燈，覺皇舍利寶煙凝。", "山門推上三更月，似照前朝禮拜僧。"]'),
('3c77a970-d7ef-42fb-8973-7990708f84cc','題金陵雜興詩後十八首  其一七','李璉','宋','宋诗','song-poetry','','[]','南軒隠約夜聲微，獨詠齊梁綺靡詩。',32,'全唐诗/poet.song.185000.json','["南軒隠約夜聲微，獨詠齊梁綺靡詩。", "鬼火對山青焰短，依稀憶得獨眠時。"]'),
('df3471ff-3a3d-406d-a323-383eb71dc4bb','謁和靖先生虎丘祠堂','李道傳','宋','宋诗','song-poetry','','[]','涵養當用敬，進學在致知。',148,'全唐诗/poet.song.185000.json','["涵養當用敬，進學在致知。", "如車去隻輪，跬步不可之。", "夫子受師說，惟敬實所持。", "升堂逮易簀，參倚日在斯。", "遺言落人間，取論極研幾。", "是心要收斂，中不容毫釐。", "大學著明法，格物乃階梯。", "放心苟不收，{穴/射}格將安爲。", "古人貴爲己，末習多外馳。", "豈無實踐者，茲焉當孰歸。", "晚生拜遺像，敷衽跪陳詞。", "願言予服膺，沒齒終不渝。"]'),
('faf247d3-512f-4a31-a252-ac973a953d01','題樊漢炳墓','許奕','宋','宋诗','song-poetry','','[]','高志崢嶸局九州，直從人裏著仙籌。',64,'全唐诗/poet.song.185000.json','["高志崢嶸局九州，直從人裏著仙籌。", "青囊書在鬼神泣，黄絹詞高冰雪羞。", "槐里但知曾折角，蘭臺無復問長頭。", "玉棺夜入青雲去，山是人非白鶴愁。"]'),
('08ff8859-062c-45f1-9255-1b5a217b80d6','寄趙紫芝','潘亥','宋','宋诗','song-poetry','','[]','長安獨跨馿，一別二年餘。',48,'全唐诗/poet.song.185000.json','["長安獨跨馿，一別二年餘。", "朝士不能薦，承明空有廬。", "窗虛桐影薄，櫂冷桂花初。", "莫怪無書札，心親迹任疎。"]'),
('cb8ec04a-e72d-4423-9892-85b44b256347','送兄赴饒','潘亥','宋','宋诗','song-poetry','','[]','草堂荒蕪未春暮，乳燕安巢雁北去。',64,'全唐诗/poet.song.185000.json','["草堂荒蕪未春暮，乳燕安巢雁北去。", "回首蜃水桃始花，及至螺江柳飛絮。", "江東繡衣真御史，聞者紛紛毛髮起。", "日長惟抱空甕眠，頭白應憐故人子。"]'),
('c329bbb5-7f58-4608-83e7-ea38a3016c55','社日','潘亥','宋','宋诗','song-poetry','','[]','聽得東風急，吹乾小逕泥。',48,'全唐诗/poet.song.185000.json','["聽得東風急，吹乾小逕泥。", "雨多花放早，水滿燕飛低。", "貧女不知緯，幽人只此棲。", "依依懷去歲，摘茗白壇西。"]'),
('78ad6223-4622-47a5-8982-b1723fe7caf9','贈善書記','潘亥','宋','宋诗','song-poetry','','[]','不見十年久，緣師懶入城。',48,'全唐诗/poet.song.185000.json','["不見十年久，緣師懶入城。", "菴移五峰近，病去一身輕。", "弟子新傳業，詩人舊識名。", "依然難駐屐，空復重予情。"]'),
('a9e90b2f-31a2-4b2f-aae3-26472098cb0f','送別趙紫芝','劉正之','宋','宋诗','song-poetry','','[]','夫君落落大雅姿，聲名早與賀白馳。',144,'全唐诗/poet.song.185000.json','["夫君落落大雅姿，聲名早與賀白馳。", "錦囊千首不療饑，非詩窮人窮乃時。", "憶昔聞君未識面，獨傳句法誇清健。", "朅來白下一相逢，傾蓋論心曾幾見。", "劃然起柁春江流，我亦江頭尋去舟。", "人生相聚會有別，江水江花無盡愁。", "萬事不如歸去好，石田茅屋生春草。", "如君自是玉堂仙，輕車緩轡長安道。", "春日遲遲柳依依，攀柔條兮送君歸。"]'),
('5d98a27d-6f3c-41d6-a5aa-d1ca8fb779aa','送劉旬甫','劉正之','宋','宋诗','song-poetry','','[]','雨雪成歲暮，之子遠徂征。',72,'全唐诗/poet.song.185000.json','["雨雪成歲暮，之子遠徂征。", "酌酒起相送，慨我別離情。", "池陽實大藩，佐車屈時英。", "子行一請覲，上計趨吳京。", "良玉懷貞操，芳蘭含遠馨。", "臨歧一珍重，即此萬里程。"]'),
('b56c7009-fdd2-461a-a51e-817e10684b26','錦繡谷亭','趙善湘','宋','宋诗','song-poetry','','[]','神仙樓觀倚空欹，飛上金鰲背上騎。',64,'全唐诗/poet.song.185000.json','["神仙樓觀倚空欹，飛上金鰲背上騎。", "萬里江山成獨立，一天雲雨欲低垂。", "人間安得如斯地，事外方知有此奇。", "喚取謫仙來共話，從教習日醉題詩。"]'),
('f11aacf0-e9c3-4054-aa5a-cea529a2fbda','句','趙善湘','宋','宋诗','song-poetry','','[]','正是澄清秋雨夜，空傳玉蕊發春晴。',16,'全唐诗/poet.song.185000.json','["正是澄清秋雨夜，空傳玉蕊發春晴。"]'),
('07832d36-32db-4373-9aba-8fe628853537','詠左伯桃羊角哀墓','史彌鞏','宋','宋诗','song-poetry','','[]','餘耳當年刎頸交，所爭利害僅毫毛。',64,'全唐诗/poet.song.185000.json','["餘耳當年刎頸交，所爭利害僅毫毛。", "一朝泜水相屠戮，豈識羊哀左伯桃。", "交情切戒勤終墮，以義存心心必果。", "死生可託永無睽，自古中山說羊左。"]'),
('1f5485f7-7e74-497c-afd8-6becff05c577','和徐清叟題會江驛','曹豳','宋','宋诗','song-poetry','','[]','未到桐江上，先尋舊隠棲。',48,'全唐诗/poet.song.185000.json','["未到桐江上，先尋舊隠棲。", "水光明月夜，山影夕陽西。", "道在行藏逸，身輕得喪齊。", "更從高處看，轉覺路非迷。"]'),
('49429c61-e766-4b4a-a0cf-c15fd10ac474','春暮','曹豳','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u5b8b\u8bd7", "\u5199\u666f"]','門外無人問落花，綠陰冉冉遍天涯。',32,'全唐诗/poet.song.185000.json','["門外無人問落花，綠陰冉冉遍天涯。", "林鶑啼到無聲處，春草池邊獨聽蛙。"]'),
('103a46f3-79ed-49b0-b4a7-da7db97db72a','題括蒼馮公嶺二首  其一','曹豳','宋','宋诗','song-poetry','','[]','平蕪千里綠迢迢，水宿山行好耐勞。',32,'全唐诗/poet.song.185000.json','["平蕪千里綠迢迢，水宿山行好耐勞。", "最是愁人最奇崛，馮公之巘浙江潮。"]'),
('2ab99e63-54b0-4410-846b-42f67ea037e2','題括蒼馮公嶺二首  其二','曹豳','宋','宋诗','song-poetry','','[]','村南村北梧桐樹，山後山前白菜花。',32,'全唐诗/poet.song.185000.json','["村南村北梧桐樹，山後山前白菜花。", "莫向杜鵑啼處宿，楚鄉寒食客思家。"]'),
('13aa0e7d-a010-4471-afea-b2a8e423c8cd','上竿詩','曹豳','宋','宋诗','song-poetry','','[]','又被鑼聲送上竿，者番難似舊時難。',32,'全唐诗/poet.song.185000.json','["又被鑼聲送上竿，者番難似舊時難。", "勸君著脚須教穩，多少旁人冷眼看。"]'),
('10129efc-3b3e-4a58-8f3f-26e95df5e471','鳳凰山','曹豳','宋','宋诗','song-poetry','','[]','鳳去寥寥今幾年，至今人喚鳳凰山。',32,'全唐诗/poet.song.185000.json','["鳳去寥寥今幾年，至今人喚鳳凰山。", "只愁有鳳無人識，却指凡禽誤世間。"]'),
('862a201e-5798-41cd-bdd8-bde5aaddf8ce','元蘇二公祠','曹豳','宋','宋诗','song-poetry','','[]','兩公千載士，出處不須齊。',48,'全唐诗/poet.song.185000.json','["兩公千載士，出處不須齊。", "好事趙明府，合祠元瀼溪。", "清芬蘭馥馥，往事草萋萋。", "新額人瞻仰，知君手自題。"]'),
('af1ce42a-eee6-421d-8578-342f7f8727e1','楊柳','曹豳','宋','宋诗','song-poetry','','[]','春至風花各自榮，就中楊柳最多情。',32,'全唐诗/poet.song.185000.json','["春至風花各自榮，就中楊柳最多情。", "自從初學宮腰舞，直至飄綿不老成。"]'),
('3778ce5a-5556-49cb-bfa1-08af5aeabaf4','送周知丞之官桐廬','劉植','宋','宋诗','song-poetry','','[]','潮滿桐江上，秋風洗印時。',48,'全唐诗/poet.song.185000.json','["潮滿桐江上，秋風洗印時。", "字民知最近，占位莫嫌卑。", "紙尾書名大，松邊得句遲。", "定懷東閣老，無復寄來詩。"]'),
('3ae76c8c-bffe-41bc-a7bf-70a13e6799b3','梅','劉植','宋','宋诗','song-poetry','','[]','欲問孤山訊，蹇馿行曉晴。',48,'全唐诗/poet.song.185000.json','["欲問孤山訊，蹇馿行曉晴。", "一枝籬外見，數點雪中明。", "太潔難爲友，群芳讓作兄。", "何如伴高隠，豈必盡調羹。"]'),
('86d95b8a-cd93-452c-9d20-bb20a8f71085','送周子餘赴松陽簿','劉植','宋','宋诗','song-poetry','','[]','長松雖劇縣，主簿却優閑。',48,'全唐诗/poet.song.185000.json','["長松雖劇縣，主簿却優閑。", "溪淺清見石，齋空靜對山。", "吏嚚嫌訟省，鄉狹覺民艱。", "獨稱詩人意，行吟苔竹間。"]'),
('ecaa12da-49d5-4bfd-ac13-cf9ccd3094c1','琵琶亭下問舟','劉植','宋','宋诗','song-poetry','','[]','西亭問津處，白傅此曾遊。',48,'全唐诗/poet.song.185000.json','["西亭問津處，白傅此曾遊。", "無復錦絃曲，空停估客舟。", "拋江春浪靜，傳柝夜烽收。", "最愛廬峰峭，相隨過別州。"]'),
('8c347ff5-652e-4ccb-8837-dbe3ecda43ad','重遊仙巖觀瀑','劉植','宋','宋诗','song-poetry','','[]','四山雲霧重，况復值梅天。',48,'全唐诗/poet.song.185000.json','["四山雲霧重，况復值梅天。", "瀑注玉函碧，派從銀漢連。", "飛來三百尺，流潤幾千年。", "仙者路安在，翠蘿青靄邊。"]'),
('db437ab9-1a62-4cb9-9eb4-63112cbd37ea','送西外趙知宗','劉植','宋','宋诗','song-poetry','','[]','三山蓬閬近，賀白是仙才。',48,'全唐诗/poet.song.185000.json','["三山蓬閬近，賀白是仙才。", "去領宗盟事，知從韋素來。", "幾人留北闕，獨棹向南臺。", "踏雨江頭別，西陵潮已迴。"]'),
('5eedd77a-71e2-4d6a-9141-3be7744a111a','題王憲使滄浪閣','劉植','宋','宋诗','song-poetry','','[]','城池浸空碧，鑒影復觀心。',48,'全唐诗/poet.song.185000.json','["城池浸空碧，鑒影復觀心。", "孺子去何在，此歌傳至今。", "一奩凉月白，萬井市聲沉。", "坎止寧勞問，憑欄意獨深。"]'),
('5c71cd94-723a-4b92-bd50-2382c0ac7c73','過彭澤','劉植','宋','宋诗','song-poetry','','[]','井邑已非舊，柴桑里尚存。',48,'全唐诗/poet.song.185000.json','["井邑已非舊，柴桑里尚存。", "春風三畝宅，落日數家村。", "隔樹聞鷄犬，編氓半子孫。", "頹然孤壠在，寒菊繞松根。"]'),
('4541decd-d5d4-49f7-bc65-7c625488ec6c','漁父','劉植','宋','宋诗','song-poetry','','[]','生不事農耕，悠然一舸輕。',48,'全唐诗/poet.song.185000.json','["生不事農耕，悠然一舸輕。", "沅湘依舊綠，秦漢幾回更。", "晚膾雜香茝，夜醺歌濯纓。", "豈同馳騖者，祇欲釣虛名。"]'),
('836cf9b1-1f16-4903-9ecc-bfa4b2efe71f','種玉亭爲黄元信賦','劉植','宋','宋诗','song-poetry','','[]','鋤徧蒼苔色，梅花近地移。',48,'全唐诗/poet.song.185000.json','["鋤徧蒼苔色，梅花近地移。", "山深藏美璞，春到長新枝。", "草木初分潤，冰霜久結知。", "百年封殖在，終與鼎鬵期。"]'),
('5b3bef6a-1bb4-46d5-96ef-0479970fc019','賦鰣魚得真字','劉植','宋','宋诗','song-poetry','','[]','寒碧湛無塵，前溪得細鱗。',48,'全唐诗/poet.song.185000.json','["寒碧湛無塵，前溪得細鱗。", "香堪配杞菊，味不數菰蓴。", "玉露雙酘熟，秋風一筯新。", "釣緡吾自有，何用覓玄真。"]'),
('fa771d81-bd2d-4647-a8c2-a3ae03ffd18c','丙午普覺看梅','劉植','宋','宋诗','song-poetry','','[]','寂寂西巖寺，何人訪靜來。',48,'全唐诗/poet.song.185000.json','["寂寂西巖寺，何人訪靜來。", "重尋舊遊地，惟有道師梅。", "樹蠹應留雪，香清不受埃。", "可堪玄鬢改，春已隔年催。"]'),
('ddf78175-61fd-4b4f-96d9-f2f24eebebf4','呈葉先生侍郎','劉植','宋','宋诗','song-poetry','','[]','位雖奎閣貴，獨處一齋空。',48,'全唐诗/poet.song.185000.json','["位雖奎閣貴，獨處一齋空。", "還以經綸事，全歸著述中。", "閑心同野水，煦物盡春風。", "掩面將何向，西楹奠已終。"]'),
('980c2ca1-b273-4f7a-a782-62c810f05b07','喜曹東畎遷大理寺簿','劉植','宋','宋诗','song-poetry','','[]','九衢多雨後，庭下草痕新。',48,'全唐诗/poet.song.185000.json','["九衢多雨後，庭下草痕新。", "終擬持平手，來爲折檻人。", "印開桐蔭午，吟久燭花春。", "却恨無來客，分題寄所親。"]'),
('00f61782-3d4b-4ed3-a1f2-bde7af3021aa','嘉禾興聖院','劉植','宋','宋诗','song-poetry','','[]','禪關自幽闃，竹亦號真如。',48,'全唐诗/poet.song.185000.json','["禪關自幽闃，竹亦號真如。", "况是龍潜地，曾經鳳食餘。", "土深抱節密，林凈著行疏。", "誰謂乾淳達，清陰只似初。"]'),
('5fe90756-a425-40ea-a638-de20cd7f4f08','重遊法空寺','劉植','宋','宋诗','song-poetry','','[]','寺在方山頂，山深不厭登。',48,'全唐诗/poet.song.185000.json','["寺在方山頂，山深不厭登。", "瀑飛明月峽，橋渡夕陽僧。", "萬法元皆妄，餘生了未能。", "纍纍塔邊塚，幾見谷爲陵。"]'),
('a28d9d1c-5d09-4d49-b08d-15d41d921896','悼盧次元','劉植','宋','宋诗','song-poetry','','[]','屈賈幽沉地，單車去不歸。',48,'全唐诗/poet.song.185000.json','["屈賈幽沉地，單車去不歸。", "湘江清見底，吟魄遠何依。", "行旐衝殘雨，新楸掩落暉。", "誰收遺篋藁，有子未勝衣。"]'),
('2b141201-80b4-4916-be7a-310395483f60','失題','劉植','宋','宋诗','song-poetry','','[]','此是夕郎宅，曾經左緯吟。',48,'全唐诗/poet.song.185000.json','["此是夕郎宅，曾經左緯吟。", "數聯漁父曲，萬頃碧波心。", "月上白蘋渚，秋生古樹陰。", "當年濯纓處，清徹到如今。"]'),
('670d1fcb-ee3e-4112-bf01-00f8fe49942a','答東閣','劉植','宋','宋诗','song-poetry','','[]','盎乏儲空謾自豪，掬泉當酒味尤高。',64,'全唐诗/poet.song.185000.json','["盎乏儲空謾自豪，掬泉當酒味尤高。", "賣文近覺馬卿倦，脫贈今無范叔袍。", "松下耕樵相爾汝，人間膏火自煎熬。", "荆山山裡山如壁，壁罅猶堪種碧桃。"]'),
('b843ff9e-8dcf-455c-a545-362c58149830','看梅呈同遊東閣清源','劉植','宋','宋诗','song-poetry','','[]','此樹何年向此栽，孤根低倚佛樓臺。',64,'全唐诗/poet.song.185000.json','["此樹何年向此栽，孤根低倚佛樓臺。", "不嫌幽壑逢春晚，獨在空庭立雪來。", "一段精神肪玉潤，數松掩映翠屏開。", "知心藉爾歲寒友，每到花邊不忍回。"]'),
('c4434ddd-8984-46fa-aa71-c01af145c3ab','靜樂趙觀文挽詞','劉植','宋','宋诗','song-poetry','','[]','大星殞地寂無光，硯席凝塵閟野堂。',64,'全唐诗/poet.song.185000.json','["大星殞地寂無光，硯席凝塵閟野堂。", "一老海濱天下憗，百年江左恨空長。", "家傳遺稿歸中秘，帝錄元勳紀太常。", "路遠生芻來未得，淚乾門下老劉郎。"]'),
('78fb6ca8-6f55-410b-9795-8ae26355edd1','題薛氏園','劉植','宋','宋诗','song-poetry','','[]','屋頭深鎖嶼頭雲，高下亭臺景旋分。',64,'全唐诗/poet.song.185000.json','["屋頭深鎖嶼頭雲，高下亭臺景旋分。", "荷氣曉來迎露看，泉聲雨後隔溪聞。", "疏櫺不礙松蘿月，高柳時停鷗鷺羣。", "只恐此身閑未得，徵書催發暑如焚。"]'),
('a79e4e6e-3be4-4312-9301-52ce10dcf89b','文會飛霞觀','劉植','宋','宋诗','song-poetry','','[]','水滿平川月滿船，船輕撐入藕花邊。',64,'全唐诗/poet.song.185000.json','["水滿平川月滿船，船輕撐入藕花邊。", "移來謝守巖前坐，疑是容成洞裏仙。", "茶竈烟遮松際鶴，絲桐聲雜樹頭蟬。", "明朝更踐彌明約，句擬當年石鼎聯。"]'),
('67ac79f4-18e6-4add-93e4-5f2219a7992c','潯陽江樓','劉植','宋','宋诗','song-poetry','','[]','樓壓潯陽地望雄，四無倚著拄晴空。',64,'全唐诗/poet.song.185000.json','["樓壓潯陽地望雄，四無倚著拄晴空。", "九支江匯欄干外，雙劍峰明霧靄中。", "庾令聲名猶昨日，屈平蘭芷又薰風。", "綢繆牖戶知何計，須及長淮棗未紅。"]'),
('640c5155-ebf1-4dc5-9d9e-4112aeca2940','鳳凰臺','劉植','宋','宋诗','song-poetry','','[]','昔年禪誦地，荒草夕陽臺。',48,'全唐诗/poet.song.185000.json','["昔年禪誦地，荒草夕陽臺。", "儀鳳有誰識，游人獨上來。", "古桐陰覆井，叢竹筍穿苔。", "千古幾興廢，北風吹雁回。"]'),
('4bd1c845-c93a-461d-a8b6-4710c981451f','烏駐道中','王顯世','宋','宋诗','song-poetry','','[]','蹲鴟用事謝黄獨，木奴弄色陵烏椑。',64,'全唐诗/poet.song.185000.json','["蹲鴟用事謝黄獨，木奴弄色陵烏椑。", "落日人行桑柘裏，西風雁過稻粱時。", "故山秋晚正如此，遊子天寒何所之。", "一笑沙禽忽驚去，水邊的皪早橫枝。"]'),
('27d716c5-10b3-4b40-a912-a2d6d02e061d','詩一首','王象祖','宋','宋诗','song-poetry','','[]','臯夔周公佐中古，蕭曹房杜興漢唐。',32,'全唐诗/poet.song.185000.json','["臯夔周公佐中古，蕭曹房杜興漢唐。", "因時因事修治效，不談道學亦何妨。"]'),
('3b6acfe3-0022-42d5-8145-04ac70ce829c','遊潯州南山','江邦佐','宋','宋诗','song-poetry','','[]','南山特地森奇峰，嶙峋怪石盤虬龍。',192,'全唐诗/poet.song.185000.json','["南山特地森奇峰，嶙峋怪石盤虬龍。", "巨靈夜半擘山腹，幻出巖竇相玲瓏。", "陰陽石罅滴瓊液，拂拂洞戶生天風。", "宸章炳煥神物護，斷碑零落蒼苔封。", "稚川飛昇歲月久，丹竈灰冷留遺蹤。", "曉猿夜鶴自驚怨，朝嵐夕靄常溟濛。", "我來依守困朱墨，欲尋勝概嗟無從。", "公餘乘興一登覽，萬象獻狀來無窮。", "金莖濯露素秋節，清凉不與世人同。", "憑虛孤嘯岸巾幘，收拾爽氣歸胸中。", "俗駕自憐難久駐，還作泠然御風去。", "太息真仙杳不逢，碧雲暮合空凝竚。"]'),
('3064b6e8-363e-43c2-a830-48b782c63366','亦佳亭','江邦佐','宋','宋诗','song-poetry','','[]','小亭新築亦佳哉，花木無多手自栽。',32,'全唐诗/poet.song.185000.json','["小亭新築亦佳哉，花木無多手自栽。", "若謂甘棠安敢比，清陰留與後人來。"]'),
('2db9c026-1022-453b-961b-407ffbfcd3ea','瓊花  其一','鄭損','宋','宋诗','song-poetry','','[]','瓊花今日多從辯，玉蘂唐人早有詩。',64,'全唐诗/poet.song.185000.json','["瓊花今日多從辯，玉蘂唐人早有詩。", "天上神仙曾枉駕，世間草木敢連枝。", "無風亦識飄香處，有眼誰看墮地時。", "三十年來成一夢，摩挲石刻鬢添絲。"]'),
('7d3a5ed6-8fb0-4eb3-9a35-417b7459856e','瓊花  其二','鄭損','宋','宋诗','song-poetry','','[]','春晚驅車到古祠，看花復誦舊題詩。',64,'全唐诗/poet.song.185000.json','["春晚驅車到古祠，看花復誦舊題詩。", "少年嘗記六七月，大暑曾開三五枝。", "酹酒輒來思往事，凭闌欲去立多時。", "八仙彷彿多疑似，相隔仙凡只一絲。"]'),
('3c0aa3f2-1dd6-4c28-9915-41aa68719f18','瓊花行','樓鎌','宋','宋诗','song-poetry','','[]','瓊花未信無雙無，特與翔鶴游江都。',168,'全唐诗/poet.song.185000.json','["瓊花未信無雙無，特與翔鶴游江都。", "炷香展敬下古殿，相羊盤礴亭南隅。", "我欲歌之詞，我欲聲之詩。", "龍蛇滿四壁，妍醜紛淋漓。", "一笑訊花花不語，斯須花以臆對之。", "自從天上來蕃釐，墨卿楚客知心誰。", "本來有是自三異，惠肅一辯公寵賁。", "厥今太守有父風，兩句寫出無雙意。", "直教彈壓千萬春，香不隨風潛墮地。", "我聞此語警且喜，不孤迢遞來千里。", "花兮報稱爲如何，年年三月花開多。"]'),
('499bfaae-68e9-4c4e-8949-9798af30b727','白鷺亭','羅愚','宋','宋诗','song-poetry','','[]','千古城頭白鷺亭，鷺飛長是滿江汀。',32,'全唐诗/poet.song.185000.json','["千古城頭白鷺亭，鷺飛長是滿江汀。", "如何覽德輝臺上，只有臺存鳳不靈。"]'),
('c012d397-f249-4a15-9e42-22ced9e4d24b','存目','羅愚','宋','宋诗','song-poetry','','[]','詩題:龍巖寺首句：直上龍巖第一層。',17,'全唐诗/poet.song.185000.json','["詩題:龍巖寺首句：直上龍巖第一層。"]'),
('5d7b7aad-416f-45de-a8a8-576019d77b8e','廬山歌','陳宓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山清哉誰與儔兮，嶄巖峭直跨番昜彭蠡而蹴九江。',296,'全唐诗/poet.song.185000.json','["廬山清哉誰與儔兮，嶄巖峭直跨番昜彭蠡而蹴九江。", "長川幽窞亙古今而不息兮，雨激而風撞。", "山深境寂人迹所希到兮，盡日僅一逄樵叟鶴髮而眉厖。", "路逶迤而險阻兮，越數千里之危谾。", "暑六月而不知兮，但覺鳴珂戞珮其下紛淙淙。", "天隔車馬之氛埃兮，獨許策杖而踰矼。", "宜幽人之履道兮，志精一而匪哤。", "草木堅勁而不凋兮，列雲外之羽幢。", "如凝之之潔白兮，媲茲山而爲雙。", "田多瘠而少腴兮，食不飽而體不痝。", "青松爲醪呼月爲燭兮，漥尊瓢飲孰取乎瓊巵而翠缸。", "彼叢物欲以自蔽兮，莫爲之鑿通明之八窗。", "醉生夢死真蟪蛄兮，閲千萬歲獨有貞柏與聖玒。", "苟能保此而不渝兮，又何有乎施邦。", "一到令人不忘兮，長神醉而心降。", "寫此詩以自娛兮，當萬幅之圖畫而揭以千仞之杠。"]'),
('0200a3ea-1446-4ab1-be6e-c8576d6c6496','西湖歌','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夫君之遊兮，嫣荷爲之笑迎。',96,'全唐诗/poet.song.185000.json','["夫君之遊兮，嫣荷爲之笑迎。", "夫君之歸兮，白鷺爲之致情。", "嗟此湖幾千百年兮，曷嘗遇夫夫君之清。", "人如玉兮水如鏡，雨如珠兮山如屏，我爲此歌兮不知誰爲之聲。", "抑天籟之自鳴，抑性情之自生。", "風卷其紙，陶然忘形。"]'),
('ae958e10-a648-47af-a183-eb77d8c28629','讀史偶題','陳宓','宋','宋诗','song-poetry','','[]','長孺濮陽人，十世士於衛。',108,'全唐诗/poet.song.185000.json','["長孺濮陽人，十世士於衛。", "矯制發倉廩，河內被恩霈。", "辭令守東海，卧閣動經歲。", "田蚡與衛青，未嘗屈其貴。", "張湯每遭駡，刀筆忝廷尉。", "無知五百人，闌出實何罪。", "犯顔爲力諫，武帝不知愧。", "十年死淮陽，不入禁闥內。", "嗚呼社稷臣，傅爰豈其配。"]'),
('2e7b002b-b381-4bc7-8c62-932e016ffc16','偶題  其一','陳宓','宋','宋诗','song-poetry','','[]','周黨不受祿，嚴光不爲公。',60,'全唐诗/poet.song.185000.json','["周黨不受祿，嚴光不爲公。", "皆當建武聖，固守空山窮。", "丈夫各有志，未必不合中。", "所以二百載，鴻基繫清風。", "彼淺者若人，一羽重於躬。"]'),
('32f24cf8-16df-41a3-bb68-b5dda865d2eb','偶題  其二','陳宓','宋','宋诗','song-poetry','','[]','向長不願富，折像患不貧。',48,'全唐诗/poet.song.185000.json','["向長不願富，折像患不貧。", "奇禍伏所慕，藏身有餘珍。", "向來東陵侯，豈似種瓜人。", "茫茫宇宙間，不得自由身。"]'),
('223050c6-5443-4a73-bfe5-cbd93067926a','讀史','陳宓','宋','宋诗','song-poetry','','[]','巧哉呂相國，千金買名姬。',48,'全唐诗/poet.song.185000.json','["巧哉呂相國，千金買名姬。", "設計售子楚，自詫居貨奇。", "一死博富貴，大黠寧非癡。", "人力信莫及，天道吾不欺。"]'),
('61b87bf5-91f5-482e-b418-ec3572e00a56','讀史','陳宓','宋','宋诗','song-poetry','','[]','子房真男子，五世相韓國。',108,'全唐诗/poet.song.185000.json','["子房真男子，五世相韓國。", "父死未及仕，不受暴秦辱。", "家僮三百人，求客不顧族。", "持說說項梁，立成宗社復。", "梁亡羽不遣，事漢羽亦覆。", "眇然一身微，兩暴以足蹴。", "由來蚤學禮，大義滅私欲。", "俯仰既無愧，何須真辟穀。", "遂令萬世後，嘆詠長不足。"]'),
('986254c2-e31e-4c75-a16b-15741ebefec5','懷古  其一','陳宓','宋','宋诗','song-poetry','','[]','不憂不慍顔氏子，載色載笑陶淵明。',32,'全唐诗/poet.song.185000.json','["不憂不慍顔氏子，載色載笑陶淵明。", "萬頃黄陂撓不動，三賢萬世仰高名。"]'),
('68a01100-4e34-4052-90a5-aa5925f157bb','懷古  其二','陳宓','宋','宋诗','song-poetry','','[]','羲之誓墓終不仕，幼輿挑女因折齒。',32,'全唐诗/poet.song.185000.json','["羲之誓墓終不仕，幼輿挑女因折齒。", "清高足以激懦貪，曠達端能喪廉耻。"]'),
('8e7dca41-f938-46fe-a98e-3e6a74b1ebb9','偶題','陳宓','宋','宋诗','song-poetry','','[]','竇姬欲趙誤至代，昭君色妍還作醜。',32,'全唐诗/poet.song.185000.json','["竇姬欲趙誤至代，昭君色妍還作醜。", "信知天命不可移，舉世奔趨果何有。"]'),
('eb0917be-4493-46eb-b203-132e9f3198aa','讀詩','陳宓','宋','宋诗','song-poetry','','[]','舉世莫遮太白眼，無物可解杜陵懷。',32,'全唐诗/poet.song.185000.json','["舉世莫遮太白眼，無物可解杜陵懷。", "當時悔不更痛飲，後世浮名安用哉。"]'),
('e330345f-a012-4b44-9fad-70bebda0deec','和樞上人評詩','陳宓','宋','宋诗','song-poetry','','[]','贈我古錦囊，詩卷若笋束。',288,'全唐诗/poet.song.185000.json','["贈我古錦囊，詩卷若笋束。", "吟頭久不掉，邂逅適我欲。", "刺眼訝龍蛇，遠意追鴻鵠。", "陋語固自媿，高詞敢虛辱。", "大雅久矣亡，三嘆對遺牘。", "不有靖節篇，何以悅我目。", "謫仙句無敵，有口不食粟。", "遂令後世儒，拳拳仰高躅。", "杜陵到聖處，正始頓牽復。", "揮毫動風雨，咳唾驚流俗。", "其餘閙鼃蚓，誰屑與類族。", "亡國悅鄭音，俚耳習胡曲。", "勃興出韓柳，一洗陋學獨。", "變化雲在天，鮮妍錦來蜀。", "驊騮就夷路，造父爲之僕。", "方揚秋月輝，忽散春花馥。", "洪鈞運不停，常窘苦見逐。", "我宋得歐蘇，妙語起山谷。", "后山又角立，作者復陸續。", "流派自天河，巨浪翻平陸。", "和風扇寰宇，絃誦興庠塾。", "搏虎寢其皮，屠龍食其肉。", "擲簡海蜃浮，舉手天漿掬。", "會當三月初，論文約吾屬。"]'),
('bcfa9d3d-7084-4cf8-b5b2-9b99815fe27e','八三姪借半山詩因以示之','陳宓','宋','宋诗','song-poetry','','[]','我讀半山詩，瞠乎不可及。',120,'全唐诗/poet.song.185000.json','["我讀半山詩，瞠乎不可及。", "風騷融老腹，取次有掇拾。", "清放太白章，悲壯杜陵集。", "爭雄而競秀，鼎峙高嶪岌。", "譬將雲作錦，絢爛那得襲。", "又如月長新，纖圿不可入。", "山川謝佳麗，風雷怯呼吸。", "想當下筆時，會見真宰泣。", "惜哉有此奇，孔室未許入。", "當時死翰死，顔孟庶并立。"]'),
('f6f09c95-1d36-4889-bc86-b0b186731560','病後寄鄭自正','陳宓','宋','宋诗','song-poetry','','[]','卧病六十朝，尪羸欲顛躓。',288,'全唐诗/poet.song.185000.json','["卧病六十朝，尪羸欲顛躓。", "中虛苦暴下，外怯因多涕。", "風邪動感觸，寒熱肆留滯。", "百病果難堪，未免趣醫至。", "携持篚與篋，衆藥要盡試。", "㕮咀和參朮，煎煮雜薑桂。", "了無銖寸功，徒有千百累。", "金丹號起死，入腹作鼎沸。", "服之不能瘳，束手信無計。", "嗟余有天命，未許藥石治。", "再拜謝群醫，云病且平易。", "堆床屏丸散，養體親滋味。", "曾不數閲日，頗能安寢寐。", "昨朝偶尋鏡，自喜有瘥意。", "俄驚一目赤，灸灼如頳尾。", "薰療技已窮，赤勢殊未既。", "平旦澀難開，未晚痛先閉。", "于何我久病，復有此兢悸。", "當時呻吟餘，猶解閲文字。", "茲焉眼如瞽，把卷直欲棄。", "舊書滿窗几，日讀不省記。", "賦性已不靈，此疾胡可被。", "悲來祇頭低，坐處每酸鼻。", "何時雙眼明，一覽經滿笥。"]'),
('902af3b6-6b7d-412e-9edd-be954a00be52','檄中原','陳宓','宋','宋诗','song-poetry','','[]','大哉我宋得天下，仁比三代澤過之。',320,'全唐诗/poet.song.185000.json','["大哉我宋得天下，仁比三代澤過之。", "太祖太宗貽典則，真宗仁考父母慈。", "熙豐足國振百度，要使宇內無蠻夷。", "哲宗元祐建皇極，敬用賢哲如蓍龜。", "百年上下享安泰，萬里一域惟熙熙。", "春陽浩蕩不肅物，遂使異類窺京師。", "當時臣子不知義，視虜豺豹身狐狸。", "曲生苟活竟亦死，甘墮狡計寧非癡。", "三光晦昧五岳墜，二聖北狩無還期。", "忠臣至今痛入髓，下逮童騃猶歔欷。", "嗟爾中原舊豪傑，久效左衽心何爲。", "譬如屈伏猛獸下，荷戈伺便當乘機。", "如何顔厚不媿耻，反助貙虎爲熊羆。", "數窮六十又且半，天意悔禍人知思。", "王師六月降時雨，灑爾萬國蘇鰥嫠。", "汝猶不念汝祖父，靖康狄禍幾無遺。", "子孫壯大不能報，臣妾讐虜稱男兒。", "天戈所麾速響應，拯汝塗炭革汝非。", "吾皇仁聖又恭儉，視民如子傷如饑。", "汝今效順謹勿遲，同我四海長歡嬉。"]'),
('5398567a-8af9-4b30-95e6-0f7e292e29fa','和徐紹奕','陳宓','宋','宋诗','song-poetry','','[]','將軍承天寵，建此油幢碧。',240,'全唐诗/poet.song.185000.json','["將軍承天寵，建此油幢碧。", "喑嗚指顧間，匈奴期伏鑕。", "堂堂帷幄算，暨暨貔貅力。", "填填畫鼓鳴，爍爍紅旗植。", "風高戰場古，萬里快驅轢。", "軒昂國士知，痛憤平城厄。", "兵求結髮戰，馬作騰槽躑。", "英聲陵鬼方，義氣殫禹迹。", "書馳羽檄忙，陣布魚麗戢。", "漫天塵霧黄，照夜戈鋋白。", "羌胡那敢鬭，枕籍多於簀。", "駢頸亟賣降，析骸仍乞食。", "君文比武事，雄偉世共識。", "顧我敢言勇，殆類殿奔策。", "它年後從車，萬一效寸尺。", "聲名蠻貊間，難避江湖僻。", "冥心進取地，高節空介特。", "囊錐不可隠，穎脫在朝夕。", "麗詞工錦繡，妙語珍渠珀。", "何時驅俗氛，相會不旬隔。"]'),
('03efbb57-40f9-482e-a014-a1b1b438160e','和徐紹奕昭君圖','陳宓','宋','宋诗','song-poetry','','[]','漢家無計餌單于，掖庭爲出千金姝。',147,'全唐诗/poet.song.185000.json','["漢家無計餌單于，掖庭爲出千金姝。", "秀色妍姿玉不如，天子一見先嗟吁。", "三千粉黛爾殊絕，謀身獨拙何蠢愚。", "梨花带雨辭殿隅，遺恨畫工猶可誅。", "世人重色多欷歔，不思婉孌同戈殳。", "君王蚤識應耽娛，皇天爲遣投穹廬。", "乃知漢計自不疎，畫工憂國非姦諛。", "君不見後世佳人號太真，坐令九鼎汙胡塵。", "當時早解揮妖麗，長作開元一聖君。"]'),
('0f9fd522-b85a-497e-beb7-3cbac9b5f3f7','通刺師道弟','陳宓','宋','宋诗','song-poetry','','[]','昔我先君子，受爵每惧盈。',192,'全唐诗/poet.song.185000.json','["昔我先君子，受爵每惧盈。", "國恩恨未報，遺訓昭誓盟。", "兩兄既即世，與子相須生。", "學問若過時，書劍兩無成。", "年各過五十，以恩厠簪纓。", "出雖稍遲滯，亦忝半刺榮。", "幸有舊田廬，勤儉可無營。", "宦遊要及物，閑居亦舒情。", "乖隔踰一年，便風勞寄聲。", "願言速加鞭，晨興課歸程。", "有親頭已白，中夜夢紆縈。", "日日遲爾至，一尊歡笑并。", "五馬固足戀，二毛還可驚。", "幸有故園竹，霜葩娛弟兄。", "豈務耳目玩，庶令心體平。", "一瓢晏共飲，詩書託餘齡。"]'),
('c1227d58-71a0-4df2-874d-409d65b5cc31','贈喻景山','陳宓','宋','宋诗','song-poetry','','[]','去時恨輕分，歸路喜忽值。',48,'全唐诗/poet.song.185000.json','["去時恨輕分，歸路喜忽值。", "如何七八月，兩作別離味。", "方衝臘雪還，可待秋風至。", "讀書我無訣，須君授奇秘。"]'),
('6ee7a040-3c31-4ce6-868c-fa06e39c20e2','和許月湖遊鼓山','陳宓','宋','宋诗','song-poetry','','[]','伐坐塵坌中，秋汗正浹背。',108,'全唐诗/poet.song.185000.json','["伐坐塵坌中，秋汗正浹背。", "聞君遊鼓山，騎馬破煙靄。", "不向曉中看，安得識眉黛。", "飄然出樊籠，始覺此身大。", "登高望四遠，何物非礪带。", "行窺靈源洞，往往衆仙會。", "青山爲佳人，分外作幽態。", "而我俗緣重，不到清凉界。", "新詩時一吟，忽在千巖外。"]'),
('dd80f595-b646-49e6-9c36-fec5a7fc5b2b','和楊縣尉五首  其一','陳宓','宋','宋诗','song-poetry','','[]','作者去千載，心事如相期。',48,'全唐诗/poet.song.185000.json','["作者去千載，心事如相期。", "嗟我苦生晚，晝想夜夢之。", "楊君妙古學，揮毫滿烏絲。", "今人有如此，可不結新知。"]'),
('b4ad7613-e29f-46f4-8437-7cc0406216f2','和楊縣尉五首  其二','陳宓','宋','宋诗','song-poetry','','[]','昧者不自覺，役役塵土中。',48,'全唐诗/poet.song.185000.json','["昧者不自覺，役役塵土中。", "丈夫意有在，肯與兒輩同。", "毫錐可濟世，不論汗馬功。", "得君起予句，使我銘諸胸。"]'),
('c8e82cf5-c435-4384-a529-12837c5649c6','和楊縣尉五首  其三','陳宓','宋','宋诗','song-poetry','','[]','後生若無聞，諸老久矣衰。',48,'全唐诗/poet.song.185000.json','["後生若無聞，諸老久矣衰。", "西蜀惜子雲，南閩見孫枝。", "文章擅妍麗，草木春葳蕤。", "從君授真訣，恐我無仙姿。"]'),
('8bd5bd1b-1d01-42be-bcaa-46ac0a6fbaa7','和楊縣尉五首  其四','陳宓','宋','宋诗','song-poetry','','[]','君詩企風雅，聖處同天工。',48,'全唐诗/poet.song.185000.json','["君詩企風雅，聖處同天工。", "筆陣有前敵，一戰可勒功。", "夜光謝牛斗，耿耿崔嵬凶。", "肯顧馬千駟，甘心因詩窮。"]'),
('fedddb24-fdb8-4c97-b14b-28b8b5681fb8','和楊縣尉五首  其五','陳宓','宋','宋诗','song-poetry','','[]','下帷抱遺經，比鄰窺半面。',48,'全唐诗/poet.song.185000.json','["下帷抱遺經，比鄰窺半面。", "萬里上鵬程，九秋騫鶚薦。", "君乎真可人，我實未幾見。", "請爲金石交，功名期鐵研。"]'),
('019e484b-98a7-4cd9-9f5a-a76c26203585','和陳教','陳宓','宋','宋诗','song-poetry','','[]','昔我壬子歲，辭家莆山陽。',288,'全唐诗/poet.song.185000.json','["昔我壬子歲，辭家莆山陽。", "迎婦丞相府，調官君子鄉。", "于時公聲名，豈獨梁楚揚。", "聞者盡興起，見者齋以莊。", "英華發經笥，土苴遺巾箱。", "虎蔚管庸見，海鉅蠡可量。", "伏波少已勇，捷出翰墨場。", "遺我明月珠，一見心先凉。", "擲地戞清玉，映日開炎光。", "春雲可比態，百卉羞無芳。", "下顧陰何輩，頡頏李杜行。", "不知生最晚，磊磊何相望。", "文臻韓氏奧，學升夫子堂。", "道貫參曾唯，心悟顔齋忘。", "所讀者何書，誦此虞與唐。", "所敬者何物，瞻彼昊與蒼。", "仁義久已熟，出言如探囊。", "又同沖霄鶴，舉世避軒昂。", "斯文尚何俟，木鐸天其將。", "六經作黄麻，一賦卑長楊。", "厚賜顧曷報，有類相馬償。", "但當銘之心，刻珮聯琳琅。", "區區重此來，得遂舉一觴。", "灑然如熱濯，車輪寬別腸。"]'),
('8a1cb10b-8da6-4963-b69b-1b4b2c6b4380','和王主簿韵  其一','陳宓','宋','宋诗','song-poetry','','[]','黄葉逐西風，歸心與俱起。',84,'全唐诗/poet.song.185000.json','["黄葉逐西風，歸心與俱起。", "况復懷美人，相望一溪水。", "聞名知幾年，會面數月耳。", "如何於其間，四旬還索處。", "美人志前脩，脂車日千里。", "平生潔白行，尺璧絕瑕指。", "持以照寒溪，溪澄疑有滓。"]'),
('0167106b-0386-4448-939d-d0580efd62d3','和王主簿韵  其二','陳宓','宋','宋诗','song-poetry','','[]','飛烏啞啞鳴，未倦投深枝。',144,'全唐诗/poet.song.185000.json','["飛烏啞啞鳴，未倦投深枝。", "如何三年仕，束带事韉羈。", "丈夫志有在，豈爲日再炊。", "事業不足道，空成楚冠縻。", "有時屏朱墨，靜坐欲無爲。", "不復顧目前，屠沽鬭群兒。", "食焉不能怠，况有尸素譏。", "風俗幸朴茂，不與驕侈期。", "撫摩雅無術，一稔適登時。", "吏議尚見貸，茲懷敢萌欺。", "一日事必葺，九仞功易隳。", "垂滿得佳友，天憐愚頓姿。"]'),
('23cd4276-351a-45d8-9bb6-dac4a2faa195','某嘗次贊府盧丈高韵復承見示佳篇嘆詠之餘輒成二首  其一','陳宓','宋','宋诗','song-poetry','','[]','盧君真吏師，盛名日方起。',84,'全唐诗/poet.song.185000.json','["盧君真吏師，盛名日方起。", "我昔嘗與言，如以石投水。", "初聽已瑩心，久坐益醒耳。", "如何但悁企，不得親燕處。", "經年始再見，相望才百里。", "新詩忽來前，喜染大羹指。", "詞翰與其人，俱清絕塵滓。"]'),
('a877fcec-4a18-4ec4-a1aa-0b43907d0272','某嘗次贊府盧丈高韵復承見示佳篇嘆詠之餘輒成二首  其二','陳宓','宋','宋诗','song-poetry','','[]','家山四年別，梅萼忽橫枝。',144,'全唐诗/poet.song.185000.json','["家山四年別，梅萼忽橫枝。", "久擬投倦翼，還成效雌羈。", "初之一毫補，謾素五十炊。", "所就竟何事，敢言厭拘縻。", "吏民笑已滿，雖勤欲奚爲。", "答以事不然，吾心異群兒。", "矻矻不能閑，任汝了事譏。", "吾道日已長，天運無窮期。", "常恐業未富，無以答明時。", "歸將閉門坐，謹學毋自欺。", "刻心事仁勇，立志防怠隳。", "乞我刀圭劑，發此蒙昧姿。"]'),
('4ec906b6-aa1b-4e01-a626-04cbeee93460','和陳中行校書','陳宓','宋','宋诗','song-poetry','','[]','老梅抱奇姿，寂寞山之陽。',288,'全唐诗/poet.song.185000.json','["老梅抱奇姿，寂寞山之陽。", "風月已爲友，雲水環其鄉。", "蜂蝶不能到，林深自揚揚。", "蕭疎謝公墅，淡靜午橋莊。", "門前有遊子，跨馬服牛箱。", "衝衝自朋往，衮衮不可量。", "誰趨雪霜地，競媚桃李場。", "唯誇顔色好，豈寤道德凉。", "偉此歲寒植，千載有耿光。", "罙高萬物表，耻竝群花芳。", "剛腸逾鐵石，勁氣侵顔行。", "况有至佳實，未熟世已望。", "負以黄金鼎，登之白玉堂。", "調胹諧衆口，雋永詎可忘。", "致君高舜禹，美俗歸軒唐。", "藥石神聖主，豈但尉黔蒼。", "功名滿蠻貊，譽處還括囊。", "終始不少玷，圭璋更顒昂。", "我實愛君厚，禱頌無以將。", "所願進退節，臯夔與疏楊。", "遂使見慕徒，夙志愜以償。", "翩翩贈行詩，滿袖鳴玕琅。", "詞翰兩清絕，山陰詠壺觴。", "么微顧曷稱，皦皦在中腸。"]'),
('a103e23f-1d58-402b-88b1-8b551c88cd74','謝朱宰賦南園二十韵','陳宓','宋','宋诗','song-poetry','','[]','先君昔歸老，手自植六梅。',240,'全唐诗/poet.song.185000.json','["先君昔歸老，手自植六梅。", "結亭在人境，尺地陽春回。", "豈無林塘勝，可以榭與臺。", "自云飽世味，一室足歡咍。", "朝詩坐亭上，暮月行徘徊。", "旁觀笑不足，獨酌興攸哉。", "清風去倏遠，湫隘成鹿埃。", "經營五畝地，得此城南隈。", "鑿池壽水遶，開堂壺山來。", "脩竹翠成幄，低花錦繁堆。", "雖無亭舘巧，頗適疎散懷。", "盡日避車馬，一逕荒莓苔。", "有慚邑大夫，政成此銜杯。", "落葉風掃溉，山禽喜毰毸。", "哦詩動深谷，草木聲喧豗。", "此邦漸惠澤，耆艾到提孩。", "獨此小園植，秋芳遲君開。", "唯梅最辱愛，有句高崔嵬。", "青玉不足報，願公坐中台。", "桃李滿天下，綠野追唐裴。"]'),
('0937e151-940a-41a4-a6a5-7918ed438cc8','答李武伯','陳宓','宋','宋诗','song-poetry','','[]','李郎江西彥，傑出天與才。',168,'全唐诗/poet.song.185000.json','["李郎江西彥，傑出天與才。", "勉齋恨得晚，垂絕傾所懷。", "朅來復入閩，吾道歎已乖。", "延平有書社，四儒孔門儕。", "地勢得爽塏，山川似天開。", "群賢爲一至，君至亦少諧。", "所讀唯聖經，坦然疑無猜。", "藜藿足可飽，窗几無餘埃。", "樂天復安土，何有羈旅哉。", "所望講究精，南山賦臺來。", "如何苦吟僻，却與長吉偕。", "昔人三百篇，詞達謝剪裁。", "那用愁肝腎，推敲費安排。", "請尋顔氏樂，兀兀坐書齋。"]'),
('7ba2480e-8cb8-4604-9456-95ca5816119c','初到漁滄溪','陳宓','宋','宋诗','song-poetry','','[]','平生不到滄漁溪，邂逅相逢如有約。',160,'全唐诗/poet.song.185000.json','["平生不到滄漁溪，邂逅相逢如有約。", "遠觀已得環岫奇，俯瞰未識遊鱼樂。", "倚欄初試一銖餌，便有纖鱗最先覺。", "須臾蟻雜復蜂屯，短鬣輕鬐恣騰躍。", "小魚拙謀謾狂肆，大魚側睨無能若。", "餌浮未下衆所爭，百鳥終難勝一鶚。", "昔日魯侯思往棠，高情反被軒裳縛。", "安得如吾閑暇身，盡日相歡無適莫。", "陰春寒生尚可愛，想見六月清風濯。", "要須更待明月歸，霜雪喧豗應不惡。"]'),
('baef99a1-bf73-41cf-9586-061458e60218','重九招許真諸友登高和許韵','陳宓','宋','宋诗','song-poetry','','[]','群公錯落俱瓊瑰，胸蟠萬古高嵬崔。',116,'全唐诗/poet.song.185000.json','["群公錯落俱瓊瑰，胸蟠萬古高嵬崔。", "紅塵絕點不涴眼，更上翠壁陳尊罍。", "天低舉手挼斗柄，挹彼鉅海傾蠡杯。", "酒酣咳唾作飛雪，下視不覺蘇紘垓。", "須臾萬象著，耿耿見中台。", "蒼生墮崖下，仰首歌康哉。", "寒芒爲一正，昌運行當開。", "回光更願親蒿萊，山林自古多奇才。"]'),
('7f369d47-87f2-4676-b758-a884ff72e770','評書','陳宓','宋','宋诗','song-poetry','','[]','我非識字空有志，丱角已探翰墨場。',224,'全唐诗/poet.song.185000.json','["我非識字空有志，丱角已探翰墨場。", "于今四十竟何益，聊取上代資平章。", "率更清峭骨骼堅，雲厭古柏微春陽。", "虞君態度絕可愛，皎皎玉女乘鸞翔。", "褚君妍姿媚人眼，晚歲亦復兀老蒼。", "薛君風味寧不好，未免籍湜屢仆僵。", "太宗天性好儒翰，右軍墨寶三千張。", "君臣刻意事摹倣，往往一造夫子堂。", "終然却視不可及，長松貞潔白玉剛。", "以言其體莫減增，以言其健不屈彊。", "以言其肌不露骨，以言其媚中含霜。", "仙人溷跡在塵世，欲自揜晦終遺光。", "豈如今人作瀟洒，曼膚平脅施羅裳。", "安得刀圭換凡骨，飛上青天原此術。"]'),
('eeb29aa6-7722-4de1-9731-cbc7945fc4df','長夏歎','陳宓','宋','宋诗','song-poetry','','[]','六月不雨暘烏驕，飛蝗更剪深田苗。',96,'全唐诗/poet.song.185000.json','["六月不雨暘烏驕，飛蝗更剪深田苗。", "農夫抱衾覆一畝，背裂口焦如火燒。", "農夫農夫莫怨怒，更有無田可耕處。", "昨日長淮禾稻區，白骨成堆今莫數。", "金繒百萬去安邊，城壁不修唯壞垣。", "人言犬羊盟誓堅，我願夏日長如年。"]'),
('e8cd5a78-a403-43ff-a906-f18aa625e591','南康愛蓮即事','陳宓','宋','宋诗','song-poetry','','[]','東君倦芳菲，首夏即酣寢。',60,'全唐诗/poet.song.185000.json','["東君倦芳菲，首夏即酣寢。", "巧思蹶然興，老手更諳稔。", "殷紅間濃綠，濯此萬機錦。", "桃李謾成蹊，豈解香席枕。", "最是碧筒杯，晚凉可以飲。"]'),
('c7315fa8-e71b-4562-a0da-179f4edc58e9','與潘王二丈同遊南康郡圃致爽亭','陳宓','宋','宋诗','song-poetry','','[]','瀑秩秩而可聞，山靡靡而旁繞。',28,'全唐诗/poet.song.185000.json','["瀑秩秩而可聞，山靡靡而旁繞。", "待皓月於臺端，睇明河於木杪。"]'),
('3b80e81d-54a3-4f38-a133-771628d9208a','遊南康栖賢寺','陳宓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山東南五老峰，青天削出金芙蓉。',112,'全唐诗/poet.song.185000.json','["廬山東南五老峰，青天削出金芙蓉。", "謫仙此語誰解道，刻畫造化鴻濛中。", "我來正值小至後，暖日昭回迎朔風。", "却想冬深一奇觀，萬鶴飛舞漫蒼穹。", "金相定變作玉質，華山千丈難爲容。", "坐令胸次玉淵靜，筆下三峽波持樁。", "人生此樂豈易得，向夕城鼓還鼕鼕。"]'),
('2b6d4ee8-fbb1-4756-bdad-a099bad5cabd','南康呈潘王二丈','陳宓','宋','宋诗','song-poetry','','[]','兩載試江郡，政拙慚癃鰥。',96,'全唐诗/poet.song.185000.json','["兩載試江郡，政拙慚癃鰥。", "菖蒲值佳節，雨餘尚清寒。", "山光作翠黛，環蘸重湖寬。", "龍舟從民樂，綵袖奉親歡。", "征帆鎮今古，天際自往還。", "斑鬢閲世態，心閑如石頑。", "懷哉歸故園，千竹荷一灣。", "足了此生事，哦詩謝塵寰。"]'),
('58d5f6d8-b538-42c9-a532-ae202f856716','南康大雪','陳宓','宋','宋诗','song-poetry','','[]','嘉定己卯歲，正月十七朝。',156,'全唐诗/poet.song.185000.json','["嘉定己卯歲，正月十七朝。", "新春纔五日，大雪雱以飄。", "繽紛七晝夜，冷氣充層霄。", "朔風攪宇宙，爆耳驚秋潮。", "大厦作小舫，輕舠想浮摇。", "江湖本浩蕩，星渚尤多飈。", "常時尚閉戶，此日寒殊驕。", "行人泊前岸，只尺萬里遥。", "誰言民窶貧，積此珠與瑶。", "凍死不敢恨，千山長禾苗。", "蝗螟永入地，癘疫仍潜消。", "我得一笑歸，還家詫漁樵。", "作詩紀事實，持付村童謠。"]'),
('6e6bf00e-86ef-4bb0-a54b-5537f6567355','延平次鄭倅答田父詞韵','陳宓','宋','宋诗','song-poetry','','[]','兒饑誰與哺，衣破誰與補。',240,'全唐诗/poet.song.185000.json','["兒饑誰與哺，衣破誰與補。", "田家安樂時，尚有饑寒苦。", "况值久旱餘，十須逾缺五。", "加以瘧鬼威，空廬倍貧窶。", "我適丁此時，期以報君父。", "人言災害深，未知嗟近古。", "里閭十家聚，往往半理土。", "伊予忝芻牧，上恐負仁主。", "或婦失其夫，或子失其母。", "纍纍日就盡，公私窘捐瘠。", "此是政令乖，伊誰所自取。", "嘗乞減十算，蒼穹未蒙許。", "遂使强慚顔，繆稱事摩撫。", "日冀天色寒，舊恙或可瘉。", "如何臘已至，未有雪花舞。", "明當自投劾，待罪聽官府。", "頼有賢二車，殫心能活汝。", "萬一得歸田，終焉與樵侶。", "躬耕可足食，爲酒祀考祖。", "庶幾樗櫟材，沒齒遠斤斧。"]'),
('827019b8-f563-4849-b82c-7cabcb8dd3ec','同師道弟奉親遊延平鳳山','陳宓','宋','宋诗','song-poetry','','[]','我來一載强，再覿鳳山面。',180,'全唐诗/poet.song.185000.json','["我來一載强，再覿鳳山面。", "時當秋末垂，群木尚葱倩。", "卓彼鸞停姿，清流潔於練。", "照影眩其儀，世治乃一見。", "伊予獨何人，婁獲遇奇盼。", "去年旱少收，田里多流轉。", "今年雖得稔，舊恙復枝蔓。", "聖主肩有虞，斯瑞遂可援。", "却笑閩越氏，雖美誰與傳。", "山勢較奇崛，泉源費洿羨。", "堅松峻壁挂，暗溜陰崖濺。", "莎寒晚不彫，果異紅堪戀。", "四圍巧邏遮，千級窘攀緣。", "弟兄承板輿，向晚不知倦。", "詩成寄山中，聊用紀繾綣。"]'),
('22d33727-be84-49ab-988e-0ac899eff5bf','上巳日遊延平脩禊洞','陳宓','宋','宋诗','song-poetry','','[]','延平山水窟，平生涉其粗。',168,'全唐诗/poet.song.185000.json','["延平山水窟，平生涉其粗。", "距城五十里，岩壑難具模。", "崔嵬通上界，突兀動地樞。", "泉石自撞擊，鈞天恐難如。", "或若轟雷霆，或若唾珠璣。", "飛瀑自天下，循涯作清渠。", "云是鬼神力，巧鑿三丈餘。", "羽觴激如飛，聊助文字娛。", "崇山回環合，有洞容入居。", "覿面卓文筆，仰天真可書。", "幽花與脩竹，揜映釋氏廬。", "同遊皆勝士，適值暮春初。", "山陰未足數，直想風舞雩。", "豈無休沐日，復洗紅塵裾。"]'),
('1cdd3a12-bc2e-412b-9aba-968971ec8c7c','三月遊延平溪源','陳宓','宋','宋诗','song-poetry','','[]','溪源數里近，半載始能之。',120,'全唐诗/poet.song.185000.json','["溪源數里近，半載始能之。", "鸑鷟一峰聳，相參如有期。", "昔人卓菴地，惜不譚佇尼。", "我與五士遊，正值暮春時。", "脩梁四三所，盡得廬阜奇。", "清波映文石，珠玉光陸離。", "貪者反不顧，留爲貧窶資。", "飛雪湧千石，寧爲寒暑移。", "觸熱褦襶子，豈知世有斯。", "題名峻壁間，用愜異日思。"]'),
('f271fb39-3932-439a-acbc-e541a80b3a24','和李艮翁延平山泉韵','陳宓','宋','宋诗','song-poetry','','[]','憶在延平郡，疑觀夔府泉。',288,'全唐诗/poet.song.185000.json','["憶在延平郡，疑觀夔府泉。", "分爲萬家澤，來自九天邊。", "派別知何日，源深不計年。", "千筒如比櫛，疊節似聯鞭。", "勁健山難遏，纖微砭可穿。", "駛於河並注，捷劇箭初傳。", "玉漏長點滴，鮫珠任碎圓。", "雨時衝鴈斷，晴罷復雞連。", "融夜春冰泮，清甘曉露涓。", "藤蘿頻助固，瓜瓞莫形緜。", "濺地花長潤，飛空日倍鮮。", "用雖供甑爨，性本带雲烟。", "留暑疑無地，爲霖綽有天。", "沫飄飛絮擘，聲動佩環聯。", "勢類虹垂漢，人誇瀑挂川。", "笛從王晉弄，笙是女媧編。", "蛇青仍夭嬌，虬白更蜿蜒。", "解滌酆城氣，攻參廣教禪。", "喧令卧轉穩，靜覺坐能聖。", "松閣晨囂寂，書窗夜聽專。", "流觴情倍適，瀹茗味尤便。", "未飲襟先潔，將吟筆婁湔。", "一絲抽沼面，十仞激崖顛。", "旱日聞偏誤，秋霄思易懸。"]'),
('cc0c7273-558a-4b9d-804b-f631b65c6a1a','和傅寺丞竹隠之什 竹隠','陳宓','宋','宋诗','song-poetry','','[]','舉世謾擾擾，誰能伴南山。',36,'全唐诗/poet.song.185000.json','["舉世謾擾擾，誰能伴南山。", "新懷太守印，雅意處士閑。", "朝夕愛此君，相對一水間。"]'),
('ea751b1d-213d-488a-98b3-cd0288e9b04b','和傅寺丞竹隠之什 讀書堂','陳宓','宋','宋诗','song-poetry','','[]','閉門聲吾咿，世仰德行成。',36,'全唐诗/poet.song.185000.json','["閉門聲吾咿，世仰德行成。", "祿仕非有意，邦國須公榮。", "區區刀筆徒，未足稱股肱。"]'),
('cba1404f-0f69-4843-9932-a8b28e5a449e','和傅寺丞竹隠之什 載酒','陳宓','宋','宋诗','song-poetry','','[]','爛熳胸中辭，縱橫筆下字。',36,'全唐诗/poet.song.185000.json','["爛熳胸中辭，縱橫筆下字。", "山陰觴詠行，少長亦畢至。", "前賢豈好飲，庶以除萬事。"]'),
('68f08ef3-f7e4-4e28-bb6b-276b48a4817a','和傅寺丞竹隠之什 寒碧','陳宓','宋','宋诗','song-poetry','','[]','仙翰洒壁間，風雨來天外。',36,'全唐诗/poet.song.185000.json','["仙翰洒壁間，風雨來天外。", "高詞寫愛景，妙趣幾人會。", "階庭富桂枝，葉葉秋不墜。"]'),
('f54a02d1-5d5a-4193-b716-c069a1f7da52','和傅寺丞竹隠之什 野趣','陳宓','宋','宋诗','song-poetry','','[]','潁川治最騰，宣室擬前席。',36,'全唐诗/poet.song.185000.json','["潁川治最騰，宣室擬前席。", "豈容玉堂人，戀此野水碧。", "池荷雜岸葦，香氣散月夕。"]'),
('b624e384-c138-4c6c-80d9-a7d4397dacea','和傅寺丞竹隠之什 清風','陳宓','宋','宋诗','song-poetry','','[]','暑氣人間盛，煩襟此地開。',24,'全唐诗/poet.song.185000.json','["暑氣人間盛，煩襟此地開。", "拂雲千箇竹，不礙晚風來。"]'),
('37d4f347-3b54-4ea4-8ea3-b5ab85dda1dd','和傅寺丞竹隠之什 暖紅','陳宓','宋','宋诗','song-poetry','','[]','勁節歲寒碧，芳枝春煖紅。',24,'全唐诗/poet.song.185000.json','["勁節歲寒碧，芳枝春煖紅。", "清和夷惠德，千載尚聞風。"]'),
('2525c6df-aae0-4c27-8151-a7819eafd317','同鄭寺丞登西瀑','陳宓','宋','宋诗','song-poetry','','[]','紹年一聯鑣，作意到西瀑。',108,'全唐诗/poet.song.185000.json','["紹年一聯鑣，作意到西瀑。", "是時新喜晴，峻壁潄清玉。", "雷霆駭神覩，冰瑩雪胸腹。", "臨深足恐墮，坐石膝頻促。", "晷長不知永，玩久愈未足。", "下山歷斗潭，喧豗尚相逐。", "忽逾十五里，風雨送歸躅。", "抵家如夢覺，始覺當暑溽。", "但願身更强，後遊多秉燭。"]'),
('8f7bf920-3dac-4935-ae0f-9eecffb248b0','東湖四詠  其一','陳宓','宋','宋诗','song-poetry','','[]','我作城東湖，築堤百餘丈。',96,'全唐诗/poet.song.185000.json','["我作城東湖，築堤百餘丈。", "水深纔四尺，岸曲八回往。", "中號小滄洲，拏舟徑蓮蕩。", "迴環即數里，淥作三江漲。", "集鷺絕驚猜，跳魚時跌宕。", "欄外一峰奇，意重友人餉。", "月夕命客遊，不更蓬萊訪。", "秋凉但曝書，未許歌吹上。"]'),
('54dfe212-4e50-4dda-8fb2-c88963821b70','東湖四詠  其二','陳宓','宋','宋诗','song-poetry','','[]','胡公是吾友，千載不改節。',96,'全唐诗/poet.song.185000.json','["胡公是吾友，千載不改節。", "長作松筠青，烟雲任明滅。", "岧嶢占南面，硉兀壓城闕。", "西來群岫馳，尊敬不敢越。", "餘勢抵東海，平夷復奇崛。", "陳岩亦加禮，北坐拱相謁。", "我樓於其中，往往媿時列。", "汲汲企前脩，庶幾不見絕。"]'),
('f91afa2b-bae8-43d4-a57f-408b7e24c063','東湖四詠  其三','陳宓','宋','宋诗','song-poetry','','[]','我築屋三間，在湖東南隅。',96,'全唐诗/poet.song.185000.json','["我築屋三間，在湖東南隅。", "上號曰寬閒，觀耕風雨餘。", "下作小山房，可以讀詩書。", "維南有松竹，輕陰遶室廬。", "維北有芰荷，濃絕涵窗虛。", "四壁何所有，經訓揭砭愚。", "食息在耳目，日與聖賢居。", "園蔬尚可飽，老矣復何須。"]'),
('c449cffb-65cf-4ed8-8dbe-49281bd777a7','東湖四詠  其四','陳宓','宋','宋诗','song-poetry','','[]','西山老禪叟，依厂安數椽。',96,'全唐诗/poet.song.185000.json','["西山老禪叟，依厂安數椽。", "趺坐看東海，滄溟幾桑田。", "前此復誰居，今踰三百年。", "鍾鼓如一日，從教歲徂遷。", "人生苦浮脆，乃過金石堅。", "彼人尚能爾，况是古聖賢。", "石床對石室，靜坐思悠然。", "相期在晚暮，用以補我愆。"]'),
('4145c38f-e92d-4124-b145-63a31132e072','新池答問','陳宓','宋','宋诗','song-poetry','','[]','即宅見湖，移園就宅。',40,'全唐诗/poet.song.185000.json','["即宅見湖，移園就宅。", "以果易穀，以寬補窄。", "以娛親姻，以燕賓客。", "曰田曰園，孰失孰得。"]'),
('24cbf365-1c95-465c-87ac-b26c59bbaa4e','題傅侍郎寒碧十五韵 筠塢','陳宓','宋','宋诗','song-poetry','','[]','萍彩日相鮮，柳綿時暗度。',36,'全唐诗/poet.song.185000.json','["萍彩日相鮮，柳綿時暗度。", "無風亦生凉，有月助奇趣。", "偶來獨坐時，愛此那能去。"]'),
('10632455-16c4-4670-b71f-e3365d102701','題傅侍郎寒碧十五韵 凈凉','陳宓','宋','宋诗','song-poetry','','[]','何物擢仙質，天然契吾性。',36,'全唐诗/poet.song.185000.json','["何物擢仙質，天然契吾性。", "不染濁水泥，明月水中映。", "只許此君看，風清雨娟凈。"]'),
('1681e8d4-708f-465e-82f6-3c4400adacb4','題傅侍郎寒碧十五韵 滋蘭','陳宓','宋','宋诗','song-poetry','','[]','猗猗深林中，有類事謹獨。',36,'全唐诗/poet.song.185000.json','["猗猗深林中，有類事謹獨。", "採棄信所遭，幽芳孰榮辱。", "苦與群卉殊，千年猶有馥。"]'),
('e1c16390-ef79-47b3-b30f-d4fe81e86301','題傅侍郎寒碧十五韵 襲芳','陳宓','宋','宋诗','song-poetry','','[]','紅紫事鼎盛，嫣然媚日風。',36,'全唐诗/poet.song.185000.json','["紅紫事鼎盛，嫣然媚日風。", "香氣裊不斷，郁若篝衣烘。", "請勿別高下，一種春陽回。"]'),
('79c4041d-8284-4bc4-8900-9e3dca375592','題傅侍郎寒碧十五韵 晚香','陳宓','宋','宋诗','song-poetry','','[]','春風鬭妍麗，衆卉芳可掬。',36,'全唐诗/poet.song.185000.json','["春風鬭妍麗，衆卉芳可掬。", "丁時良亦好，暮景苦不足。", "獨擅晚秋香，金英照寒淥。"]'),
('4be64e11-08d0-4a75-b69a-bc3415c6f305','題傅侍郎寒碧十五韵 頌橘','陳宓','宋','宋诗','song-poetry','','[]','瀟湘秋氣高，群木禿如指。',36,'全唐诗/poet.song.185000.json','["瀟湘秋氣高，群木禿如指。", "粲粲朱實繁，傲霜如有喜。", "願言事封殖，勿使間棘枳。"]'),
('eb9a4989-77bb-42e1-8163-6e17d5a5cb10','題傅侍郎寒碧十五韵 種杏','陳宓','宋','宋诗','song-poetry','','[]','夭桃太繁媚，清瘦却憐梅。',36,'全唐诗/poet.song.185000.json','["夭桃太繁媚，清瘦却憐梅。", "酌此二妙質，爲君出奇開。", "釀作千日酒，高仙下崔嵬。"]'),
('30f7efbf-4834-4f9e-938c-f09ce7ee4eab','題傅侍郎寒碧十五韵 梅坡','陳宓','宋','宋诗','song-poetry','','[]','江南開最蚤，猶及仲春時。',24,'全唐诗/poet.song.185000.json','["江南開最蚤，猶及仲春時。", "此地先飛雪，多情却願遲。"]'),
