('30ca08de-b34d-4fa7-baa1-e139671f4e3f','延平倅廳十詠 風月堂','陳宓','宋','宋诗','song-poetry','','[]','奇哉山水郡，風月以爲鄉。',24,'全唐诗/poet.song.185000.json','["奇哉山水郡，風月以爲鄉。", "何人據其會，胸襟有餘凉。"]'),
('851a83c7-bd76-4035-a9a8-87d95d76cec6','延平倅廳十詠 飛霞','陳宓','宋','宋诗','song-poetry','','[]','小閣本非寬，宇宙在其內。',24,'全唐诗/poet.song.185000.json','["小閣本非寬，宇宙在其內。", "心與太初鄰，不假飛霞佩。"]'),
('054f14b0-16fc-4609-8e52-1bca46dfc1ed','延平倅廳十詠 環美','陳宓','宋','宋诗','song-poetry','','[]','昔人誇四美，勝事最難并。',24,'全唐诗/poet.song.185000.json','["昔人誇四美，勝事最難并。", "臺榭花相映，青春月正明。"]'),
('a8df6cf9-beaa-4a88-988c-314e368638ea','延平倅廳十詠 浣塵','陳宓','宋','宋诗','song-poetry','','[]','脩篁蘸方沼，常與此心通。',24,'全唐诗/poet.song.185000.json','["脩篁蘸方沼，常與此心通。", "永晝一卷書，閉拋聽泉筒。"]'),
('afd338ab-8e75-446d-9f8a-6b0abb7739a1','延平倅廳十詠 天開圖畫','陳宓','宋','宋诗','song-poetry','','[]','通衢亙其南，危樓冠其北。',24,'全唐诗/poet.song.185000.json','["通衢亙其南，危樓冠其北。", "如何境日新，烟雲爲筆墨。"]'),
('160ef4bf-e5f3-4a46-9224-9b9fb29d3b87','延平倅廳十詠 延綠','陳宓','宋','宋诗','song-poetry','','[]','紅紫漫紛紛，愛此耐久綠。',24,'全唐诗/poet.song.185000.json','["紅紫漫紛紛，愛此耐久綠。", "密幄有深處，清風起餘馥。"]'),
('dfd54ec0-9039-4c24-ba1e-4473ec262404','和柯東海遊安溪清水岩韵','陳宓','宋','宋诗','song-poetry','','[]','飛溜無時斷，行雲一日停。',144,'全唐诗/poet.song.185000.json','["飛溜無時斷，行雲一日停。", "半年嗟苦雨，三度扣禪扃。", "巖岫方從認，松篁恰得醒。", "草花多掩歛，岸竹半伶俜。", "舟子應頻喚，山農訝屢經。", "濺衣黄土重，侵屨碧泉冷。", "溪合高低白，林迷上下青。", "乍褰綿作障，重展玉爲屏。", "古佛靈如在，微官德豈馨。", "心懸炷香案，容肅換衣亭。", "晚照催歸騎，清風惜暑櫺。", "凭高閑一顧，人世是浮萍。"]'),
('cb0388c7-cef4-4055-8f72-07b871506686','南劍道中示友人','陳宓','宋','宋诗','song-poetry','','[]','坐見漫山有生意，因知此日更年華。',64,'全唐诗/poet.song.185000.json','["坐見漫山有生意，因知此日更年華。", "風和已作二月景，日煖欲破三春花。", "菜擷青青山店圃，酒沽薄薄野人家。", "吾行有涯我獨喜，盃盤雖菲君無嗟。"]'),
('94d07f1a-eb65-4148-bb3e-e95e449f6faa','瑞麥','陳宓','宋','宋诗','song-poetry','','[]','維此瑞麥，十有三莖。',40,'全唐诗/poet.song.185000.json','["維此瑞麥，十有三莖。", "伊誰所樹，中夏以生。", "豐年之慶，聖治之臻。", "我作此贊，播之頌聲。"]'),
('24ac15de-c08f-4040-8954-8642a4bc2a02','感秋','陳宓','宋','宋诗','song-poetry','','[]','西風忽起江楓末，偏喜蕭蕭弄華髮。',32,'全唐诗/poet.song.185000.json','["西風忽起江楓末，偏喜蕭蕭弄華髮。", "世間何物最堅牢，惟有古來天上月。"]'),
('60a894c6-411e-487e-96a1-cbe072b84799','歲暮','陳宓','宋','宋诗','song-poetry','','[]','我有數頃田，讀書盡歲暮。',96,'全唐诗/poet.song.185000.json','["我有數頃田，讀書盡歲暮。", "苟無饑渴態，不必羨華富。", "人生苦嗟卑，待日不可度。", "不思羲和車，去去豈反顧。", "閉門十年間，青雲半塵土。", "光榮能幾時，悔吝已莫數。", "所以五柳公，陶然樂貧窶。", "彼有五男兒，豈不後日慮。"]'),
('cf1db310-ea78-4b63-89ae-850bef73689f','五月水益小園','陳宓','宋','宋诗','song-poetry','','[]','巋然俯溪亭，偃若與舟接。',24,'全唐诗/poet.song.185000.json','["巋然俯溪亭，偃若與舟接。", "日涉有初心，風雨或闊躡。"]'),
('2a36c421-0874-41dc-86c9-942faad355b0','適興','陳宓','宋','宋诗','song-poetry','','[]','鴻鴈絕稻粱，江湖自嬉飽。',24,'全唐诗/poet.song.185000.json','["鴻鴈絕稻粱，江湖自嬉飽。", "君看太廟犧，所欠非芻藁。"]'),
('7647e31d-907e-49a2-8721-73b7ab1e5366','甘寢','陳宓','宋','宋诗','song-poetry','','[]','甘寢不易得，何人不貪睡。',48,'全唐诗/poet.song.185000.json','["甘寢不易得，何人不貪睡。", "所以八尺床，惟賢始無愧。", "萬鍾固可樂，中夜或興喟。", "誰謂顔巷貧，至寶賞所萃。"]'),
('62e634ee-9821-4d8e-a9aa-cb1b067e721a','得水蒼佩','陳宓','宋','宋诗','song-poetry','','[]','被褐磊落懷，白日凝光采。',120,'全唐诗/poet.song.185000.json','["被褐磊落懷，白日凝光采。", "初疑東君佩，擲地今猶在。", "工倕巧得之，刻畫探真宰。", "饑蛟出潜淵，怒勢吁可駭。", "憑誰縛致斯，百勇不可解。", "常恐毫髮間，捷出風雲會。", "今我隠几看，咫尺臨滄海。", "平生冰雪心，至心無由改。", "情親金石交，佩重韋弦戒。", "持身有不如，顧諟能無愧。"]'),
('d41ab166-7f09-4ea3-9fd6-0cfaa242219c','得古杉於劉坑','陳宓','宋','宋诗','song-poetry','','[]','劉坑有嘉木，根柯鍊青銅。',180,'全唐诗/poet.song.185000.json','["劉坑有嘉木，根柯鍊青銅。", "云是昔參天，森環梵王宮。", "陵谷欻遷改，風雷行地中。", "于今五百載，漁父忽相逄。", "沒淵直下覷，初驚睡驪龍。", "玩狎始一探，光怪萬仞虹。", "百夫共引綆，婁斷如飛蓬。", "一出千尋底，昂然勢摩穹。", "伊誰扶大厦，此具信足充。", "擬用作津樑，阻滯斷可通。", "斧斤一暫試，芬芳四隨風。", "胡爲久沈鬰，反羨爨下桐。", "顯晦已千載，有如初植同。", "大哉一元氣，運用無時窮。", "壽此不朽物，會與齊其終。"]'),
('abb6d5a5-9022-403b-943b-475adf7ef7d3','謝長溪張兄惠其先世所得吳氏研屏','陳宓','宋','宋诗','song-poetry','','[]','蜀産有奇石，仙人對松鶴。',60,'全唐诗/poet.song.185000.json','["蜀産有奇石，仙人對松鶴。", "文理自天成，玉質謝雕鑿。", "化工豈眩巧，賦予無適莫。", "孰謂人意殊，自作喜與愕。", "但當此堅正，俯仰無愧作。"]'),
('9993bf76-508f-4f33-b8f1-0cac9299394f','鳳咮','陳宓','宋','宋诗','song-poetry','','[]','千年寒潭底，飽孕精鋼秀。',48,'全唐诗/poet.song.185000.json','["千年寒潭底，飽孕精鋼秀。", "何人出黝玉，手觸氣如餾。", "健筆舉龍文，清音鳴鳳咮。", "坐使端歙産，瞠乎仞溪後。"]'),
('67eb2f7c-3c65-448d-af7a-8dd00cf9ff14','道間馳荔','陳宓','宋','宋诗','song-poetry','','[]','六月炎天下丹子，带露凌風日千里。',96,'全唐诗/poet.song.185000.json','["六月炎天下丹子，带露凌風日千里。", "吾皇慈儉却獻來，六宮不襲唐朝事。", "王公厭飫遠域珍，豈識宵馳常暍死。", "郡侯何用苦區區，暑氣隆時勞送似。", "色香俱壞僅存名，鳥飛不到人何勝。", "登盤乍試猶嫌味，顆顆誰知血汗成。"]'),
('e212617b-fc23-41e0-a694-ae7b78a54149','春盤','陳宓','宋','宋诗','song-poetry','','[]','清晨採擷南山麓，金刀細細裁青縠。',99,'全唐诗/poet.song.185000.json','["清晨採擷南山麓，金刀細細裁青縠。", "素盤恰辦饑雷鳴，飽覺春陽滿枯腹。", "我生頭頷非虎燕，未許嚌胾薄野䔩。", "從今葱韭藝一區，便可朝餐食無肉。", "君不見寶馬彫鞍紈絝兒，匏壺之體充甘肥。", "一生飽死同蝤蠐，夷齊至今民稱之。"]'),
('b046ea38-a109-4dda-99d2-47077935b791','謝建陽宰劉潜夫寄酒','陳宓','宋','宋诗','song-poetry','','[]','建陽則有王，桐城則有孟。',84,'全唐诗/poet.song.185000.json','["建陽則有王，桐城則有孟。", "王醖清而淳，孟盎和而勁。", "一酌適我情，再酌養我性。", "充腹皆陽和，陰慝不得並。", "或隔千里遥，或餘百里徑。", "水陸有遠近，非好遂無脛。", "苟不遇益友，吾瓶詎能罄。"]'),
('03f46945-c21a-4e3d-936e-11f51630b112','贈寒谷道人','陳宓','宋','宋诗','song-poetry','','[]','我昔過君門，心閑懶問君。',48,'全唐诗/poet.song.185000.json','["我昔過君門，心閑懶問君。", "君今來深谷，無心似孤雲。", "淋浪身上衣，磊落袖中文。", "相違復相別，去宿白鷗群。"]'),
('dcb24b47-39c5-4403-ad7c-c32a6ac206fa','白山茶雜花','陳宓','宋','宋诗','song-poetry','','[]','奇葩冬後蘂，羞澀見東風。',48,'全唐诗/poet.song.185000.json','["奇葩冬後蘂，羞澀見東風。", "不變冰霜操，從他百卉紅。", "芍藥包紅錦，橘花爛明珠。", "不復憶海棠，飄零烟雨中。"]'),
('d1d1ed68-d2ad-4398-8a4a-4da6ef65fa4d','題延平李氏宅','陳宓','宋','宋诗','song-poetry','','[]','延平李氏廬，仙翁扁盤谷。',48,'全唐诗/poet.song.185000.json','["延平李氏廬，仙翁扁盤谷。", "虛堂納水石，蘭萱和修竹。", "距城才咫尺，作吏愧真俗。", "年餘始一到，頼有客如玉。"]'),
('dfee9fa7-4df3-4a77-abe3-1986920094d5','開新池擬就僧僦地未遂','陳宓','宋','宋诗','song-poetry','','[]','一盆堪作沼，尋丈詎非塘。',48,'全唐诗/poet.song.185000.json','["一盆堪作沼，尋丈詎非塘。", "底用荷花盛，方能心境凉。", "忍將禾黍地，鑿出水雲鄉。", "極目平疇闊，時看白鷺翔。"]'),
('94dd6e62-78a0-4e17-92ba-7147c8c3ca80','易地成池','陳宓','宋','宋诗','song-poetry','','[]','南園無隙地，鑿池向園東。',48,'全唐诗/poet.song.185000.json','["南園無隙地，鑿池向園東。", "中作平臺迥，聊將小艇通。", "四圍楊柳裊，十畝芰荷紅。", "何必五湖去，門前足月風。"]'),
('f87ccb01-3fa8-4262-a112-c736b47041e5','題妙寂寺  其一','陳宓','宋','宋诗','song-poetry','','[]','四遶青巒峻，西東碧浪揚。',39,'全唐诗/poet.song.185000.json','["四遶青巒峻，西東碧浪揚。", "孤忠招寶翰，正色著祠堂。", "孰繼功言盛，空嗟草木長。", "蓼莪。"]'),
('9e449ff3-8769-4bf0-a2fb-98d5b479357a','題妙寂寺  其二','陳宓','宋','宋诗','song-poetry','','[]','百代公師墓，千年妙應林。',48,'全唐诗/poet.song.185000.json','["百代公師墓，千年妙應林。", "香隨清晝永，山泣晚秋深。", "列桂團風露，高松耐古今。", "過牆深夜月，觸目倍傷心。"]'),
('ec2e59fa-7d97-48ba-8b8b-c26c9e558059','題妙寂寺  其三','陳宓','宋','宋诗','song-poetry','','[]','寺古靜還僻，小窗幽更深。',48,'全唐诗/poet.song.185000.json','["寺古靜還僻，小窗幽更深。", "觀時知句眼，讀易見天心。", "霜露宵增感，烟雲曉見侵。", "獨坐思往昔，愁絕淚盈襟。"]'),
('48269b18-a9fb-46ed-b33e-db5c0e58f6a8','復堂獨坐','陳宓','宋','宋诗','song-poetry','','[]','漫道清明僎，真成首夏天。',48,'全唐诗/poet.song.185000.json','["漫道清明僎，真成首夏天。", "南風回礎汗，小雨駐爐煙。", "花柳無心對，詩書隠几眠。", "盃茶時猛省，事業媿先賢。"]'),
('f9067e00-3735-423d-85f1-37b6e3ce2768','荷花','陳宓','宋','宋诗','song-poetry','','[]','亭亭張翠蓋，面面覩晨妝。',48,'全唐诗/poet.song.185000.json','["亭亭張翠蓋，面面覩晨妝。", "玉鑑三千匣，金釵十二行。", "雨添驪水浴，風解月宮裳。", "對此誰能賦，端須鐵石腸。"]'),
('79c9ca3c-ea9f-4d62-a7ba-b2399e691350','竹徑','陳宓','宋','宋诗','song-poetry','','[]','新笋未全抽，春陰亦類秋。',24,'全唐诗/poet.song.185000.json','["新笋未全抽，春陰亦類秋。", "世間惟竹逕，不掃更清幽。"]'),
('9094a9e5-7521-4408-b44d-63618e32a671','即事','陳宓','宋','宋诗','song-poetry','','[]','黠鼠同姦吏，貪狡勝勇兵。',48,'全唐诗/poet.song.185000.json','["黠鼠同姦吏，貪狡勝勇兵。", "盆翻施計巧，血戰視身輕。", "拙笑龜貽患，饑憐螢獨清。", "貂蟬何物者，冠冕得光榮。"]'),
('754fd965-1baf-45c6-b603-a0346876508a','刺桐  其一','陳宓','宋','宋诗','song-poetry','','[]','名字傳輿志，風流欠畫圖。',24,'全唐诗/poet.song.185000.json','["名字傳輿志，風流欠畫圖。", "高花人不採，留得映栖烏。"]'),
('382f28ee-cd85-4732-a39c-bacea70e6d60','刺桐  其二','陳宓','宋','宋诗','song-poetry','','[]','盡護遶城家，炎風盛際花。',24,'全唐诗/poet.song.185000.json','["盡護遶城家，炎風盛際花。", "漫天何所似，漢幟雜雲霞。"]'),
('f55e5c82-846a-49e0-8d40-1dea00b2d886','題隠居','陳宓','宋','宋诗','song-poetry','','[]','磐石疑溪月，茅簷潘竹風。',24,'全唐诗/poet.song.185000.json','["磐石疑溪月，茅簷潘竹風。", "琴尊隨分有，夜夜主人公。"]'),
('b2b92184-980e-46b5-9307-ae68911ab2f6','納凉','陳宓','宋','宋诗','song-poetry','','[]','竚立金明候，清宵意豁然。',48,'全唐诗/poet.song.185000.json','["竚立金明候，清宵意豁然。", "暑風猶襲燕，秋意已通蟬。", "竹徑不知夏，漥尊別有天。", "吾曹能辦此，不媿晉林賢。"]'),
('e64a5c4a-d4da-447c-87f3-05d28f3a716f','端午','陳宓','宋','宋诗','song-poetry','','[]','雨淬菖蒲劍，雲榮角黍絲。',48,'全唐诗/poet.song.185000.json','["雨淬菖蒲劍，雲榮角黍絲。", "光陰驚老大，節物媚童兒。", "讒口千年恨，懷賢一日思。", "蘭蒿無好醜，采係用逄時。"]'),
('7cb738f9-5b9c-4541-a981-4c8fd0518981','昭君','陳宓','宋','宋诗','song-poetry','','[]','永巷鏁芳菲，春歸入燕泥。',24,'全唐诗/poet.song.185000.json','["永巷鏁芳菲，春歸入燕泥。", "粉身能報國，妾不愛蛾眉。"]'),
('17683572-3e4b-4594-8aed-a12847741533','山寺','陳宓','宋','宋诗','song-poetry','','[]','疎林漏曉日，脩竹起寒風。',24,'全唐诗/poet.song.185000.json','["疎林漏曉日，脩竹起寒風。", "鍾鼓催朝暮，千年如此同。"]'),
('ab553a0c-ef53-41c7-ba0f-9bf64dbbae92','入暮','陳宓','宋','宋诗','song-poetry','','[]','溪光延夕暝，山色接天青。',24,'全唐诗/poet.song.185000.json','["溪光延夕暝，山色接天青。", "獨立待霜月，山童已觸屏。"]'),
('bbbce1c6-8c52-4fb5-a51b-8e955f0c0c45','山中','陳宓','宋','宋诗','song-poetry','','[]','淺溪仍殘照，山青更暮烟。',48,'全唐诗/poet.song.185000.json','["淺溪仍殘照，山青更暮烟。", "人行罨畫地，鳥度粉牋天。", "麥潤先春秀，梅清破臘年。", "田家無力事，牛背落鴉眠。"]'),
('8f127841-3421-43fc-8436-7f4043a5f1a2','冰山','陳宓','宋','宋诗','song-poetry','','[]','出自重陰地，來陳酷暑天。',48,'全唐诗/poet.song.185000.json','["出自重陰地，來陳酷暑天。", "崢嶸真可仰，刻轢更成妍。", "氣與驕陽敵，峰將太華肩。", "有人心計巧，直欲厄其巔。"]'),
('40d9484a-9a44-4a72-8eb9-34b63918c4f8','謝無礙菖蒲','陳宓','宋','宋诗','song-poetry','','[]','榮枯無異態，幽寂得長生。',48,'全唐诗/poet.song.185000.json','["榮枯無異態，幽寂得長生。", "只待天河水，猶嫌玉井冰。", "松筠差少事，蘭鬰已多情。", "獨愛禪窗寒，客時几獨凭。"]'),
('9e4695b2-1677-452d-bc6c-7275bf4f1d69','宿羲丘橋','陳宓','宋','宋诗','song-poetry','','[]','月窗頻悞曉，風澗更迷晴。',48,'全唐诗/poet.song.185000.json','["月窗頻悞曉，風澗更迷晴。", "蚤欲戴星上，翻成踏雨行。", "奇峰才一面，古佛尚餘情。", "我亦愛閑者，它年尋此盟。"]'),
('462c0985-3d48-44ef-a54b-68b8a3154443','曉抵埔頭就陳氏食','陳宓','宋','宋诗','song-poetry','','[]','幸有安閑日，那無自在身。',48,'全唐诗/poet.song.185000.json','["幸有安閑日，那無自在身。", "人如年易老，詩與事長新。", "雨霽還佳境，途窮得主人。", "馳驅四十里，盤礴縣成闉。"]'),
('ba634244-9977-4156-bb77-8110f50b76bb','嚴州道中見月以禱雨不飲','陳宓','宋','宋诗','song-poetry','','[]','赤地三千里，離家四十程。',48,'全唐诗/poet.song.185000.json','["赤地三千里，離家四十程。", "豈無瓶可倒，忍對月仍明。", "在處嗟吁氣，窮村鼓鐸聲。", "有神司下土，能不惻垂情。"]'),
('4b343a52-b21d-4de9-85c5-80480340bd6f','自任所歸遊楊村鄭氏園','陳宓','宋','宋诗','song-poetry','','[]','碧柳縈沙路，紅蕖映竹扉。',48,'全唐诗/poet.song.185000.json','["碧柳縈沙路，紅蕖映竹扉。", "亭隨山作態，人與石相依。", "盛暑深巖冷，通天一逕微。", "神清非夢境，端的客來希。"]'),
('8b056163-4303-423c-8417-d3faba4cefa0','過田家','陳宓','宋','宋诗','song-poetry','','[]','足跡抵西隣，耕桑力不貧。',48,'全唐诗/poet.song.185000.json','["足跡抵西隣，耕桑力不貧。", "媼翁雙鬢雪，兒女一巵春。", "水碓春殘日，松棚香逼人。", "車中名利客，得似自由身。"]'),
('3de00d6c-8c38-45a8-a128-881ec5643f11','遊瑞泉','陳宓','宋','宋诗','song-poetry','','[]','久作靈巖想，重來一洒然。',48,'全唐诗/poet.song.185000.json','["久作靈巖想，重來一洒然。", "山排几上石，海挹研中泉。", "句出青雲外，禽歸夕照邊。", "去城曾幾遠，能不日盤旋。"]'),
('7fb8932e-9b67-4456-8a2e-4285ccbda331','到妙寂寺','陳宓','宋','宋诗','song-poetry','','[]','朝辭城市鬨，近寺向昏黄。',48,'全唐诗/poet.song.185000.json','["朝辭城市鬨，近寺向昏黄。", "步步貪山色，依依顧水光。", "群魚猶出戯，歸路倦高翔。", "正喜無人見，迎僧欲下堂。"]'),
('eb2e09cc-21b7-40d0-9d92-e70ca9023107','山居','陳宓','宋','宋诗','song-poetry','','[]','山深塵事絕，物靜壯心降。',48,'全唐诗/poet.song.185000.json','["山深塵事絕，物靜壯心降。", "蟻度輕移履，蜂迷爲穴窗。", "霜暉疑皓月，風月類翻江。", "有客來何處，應尋居士龐。"]'),
('39772fa0-8226-46e3-ac89-11bfa9fe2bbc','題先隴','陳宓','宋','宋诗','song-poetry','','[]','去去音容遠，冥冥歲月深。',24,'全唐诗/poet.song.185000.json','["去去音容遠，冥冥歲月深。", "渾將溪作淚，莫盡一生心。"]'),
('de22ef08-903d-4457-a210-c64e8bfd225e','鄂溪呈陳汝昌','陳宓','宋','宋诗','song-poetry','','[]','回鴈無來訊，違卿已十程。',48,'全唐诗/poet.song.185000.json','["回鴈無來訊，違卿已十程。", "旅懷宵不寐，歸夢曉難成。", "在處山殊秀，無溪水不清。", "平生泉石癖，亦足愜吾情。"]'),
('40f6aebb-8371-4a1a-9bde-101b4335d114','亭上茅寄生','陳宓','宋','宋诗','song-poetry','','[]','生長天垂力，孤懸有作奇。',24,'全唐诗/poet.song.185000.json','["生長天垂力，孤懸有作奇。", "最先承曉露，終不墮春泥。"]'),
('5098a949-db79-4166-99da-4814f83410fd','雨','陳宓','宋','宋诗','song-poetry','','[]','滴滴鳴乾葉，蕭蕭過短籬。',24,'全唐诗/poet.song.185000.json','["滴滴鳴乾葉，蕭蕭過短籬。", "山房欹枕夜，聽盡去來時。"]'),
('d15a1b85-5f38-47bd-8ec1-df6189f2c4f3','和度支兄詠竹','陳宓','宋','宋诗','song-poetry','','[]','園竹今逾盛，壺山與遜青。',48,'全唐诗/poet.song.185000.json','["園竹今逾盛，壺山與遜青。", "錦綳千稚子，雷甲萬夫丁。", "聲入秋風遠，凉生午日亭。", "栽培從此力，雨露正霑零。"]'),
('2d6fad89-f563-4a1c-832e-aa5523ad5ca9','和潘侯覓荔子','陳宓','宋','宋诗','song-poetry','','[]','中郎厨品在，詩老合先嘗。',48,'全唐诗/poet.song.185000.json','["中郎厨品在，詩老合先嘗。", "塵騎將星戴，筠籠柰雨妨。", "空遺黄絹句，莫致絳香囊。", "此願何當續，薰風竟一償。"]'),
('236a2ebd-75fa-4340-962c-1305e3fc5965','懷鄭文山','陳宓','宋','宋诗','song-poetry','','[]','早遂山林志，于今一代豪。',48,'全唐诗/poet.song.185000.json','["早遂山林志，于今一代豪。", "平生唯質實，四海仰孤高。", "久欲問奇字，先令餉濁醪。", "相望廿里近，可笑自塵勞。"]'),
('00fbb07e-a9a1-467e-8e10-1c483c30db41','和楊秋止酒韵','陳宓','宋','宋诗','song-poetry','','[]','快意誠甘疢，折肱知妙方。',48,'全唐诗/poet.song.185000.json','["快意誠甘疢，折肱知妙方。", "飯餘書可讀，茗過味偏長。", "南浦烟雲密，東臯耒耜忙。", "青春深幾許，明日又流觴。"]'),
('a055452f-6af2-4dfe-8789-18c4f1673b80','和許月湖上元遊東禪','陳宓','宋','宋诗','song-poetry','','[]','寺迥倫無事，山幽剩得春。',48,'全唐诗/poet.song.185000.json','["寺迥倫無事，山幽剩得春。", "天機元不斷，歲律自成新。", "禪定才朝暮，勞生幾屈伸。", "詩成人未散，月得染庭筠。"]'),
('6f549ba7-3d52-4780-9abc-806998c77fb4','送趙右史至西禪趙允中有詩和之','陳宓','宋','宋诗','song-poetry','','[]','送客此憑欄，僧閑魚更閑。',48,'全唐诗/poet.song.185000.json','["送客此憑欄，僧閑魚更閑。", "塵勞聊一釋，樂意更相關。", "誘我皆爲物，怡人獨有山。", "何時重到此，著履點苔班。"]'),
('b20d7847-7517-44f4-a4d2-5365fa69a609','西窗酴醾','陳宓','宋','宋诗','song-poetry','','[]','剪刻千條重，天上柰爾何。',48,'全唐诗/poet.song.185000.json','["剪刻千條重，天上柰爾何。", "房多攢綠玉，香遠釀春醪。", "堆架防攀折，逄人費護呵。", "不知秋桂晚，庭際長柔柯。"]'),
('81c98ec4-dce6-4450-9806-e35c5d951b6b','南園新舟成呈同遊諸友  其一','陳宓','宋','宋诗','song-poetry','','[]','虛舟當畫橋，解纜綠楊腰。',48,'全唐诗/poet.song.185000.json','["虛舟當畫橋，解纜綠楊腰。", "月白天相近，風清水不摇。", "浮圖明突兀，略彴誇虛遥。", "解逅成真賞，初晴第一宵。"]'),
('195a8fca-f70f-4066-8ccb-45f199abf19e','南園新舟成呈同遊諸友  其二','陳宓','宋','宋诗','song-poetry','','[]','暑汗俄霑背，山雲已半腰。',48,'全唐诗/poet.song.185000.json','["暑汗俄霑背，山雲已半腰。", "雷轟舟不動，電劃岸將摇。", "歷亂笑譚雜，空蒙只尺遥。", "濃陰難蔽月，清興得中宵。"]'),
('97fb0dc6-09c9-4850-b8bf-64d134d97e2a','松','陳宓','宋','宋诗','song-poetry','','[]','擎天端作柱，度漢可爲樑。',48,'全唐诗/poet.song.185000.json','["擎天端作柱，度漢可爲樑。", "不受紅塵涴，長依皦日光。", "風行揚遠韵，雨過發真香。", "偏向閩中道，炎時散午凉。"]'),
('3b9ff54c-bdce-4a6e-af75-c2d6f61d5228','春暮書房','陳宓','宋','宋诗','song-poetry','','[]','春晴無十日，秉燭亦須遊。',48,'全唐诗/poet.song.185000.json','["春晴無十日，秉燭亦須遊。", "冷笑鯫生面，黐粘蠹簡頭。", "方殫義理樂，蚤覺鬢髯秋。", "幾欲拋書坐，癡成不自由。"]'),
('f6d86156-7d87-4f85-9275-30297667224d','閲邸報','陳宓','宋','宋诗','song-poetry','','[]','虛名空自喜，叢謗亦難逃。',48,'全唐诗/poet.song.185000.json','["虛名空自喜，叢謗亦難逃。", "望重瑕來衆，官高磬折勞。", "應酬書脫腕，思慮雪侵毛。", "何似山林士，琴牀夢日高。"]'),
('dec0dff1-09c1-4b63-ba3e-a7adbbdcdf63','題高將仕墨梅','陳宓','宋','宋诗','song-poetry','','[]','露零難辨蘂，月滿祇尋香。',48,'全唐诗/poet.song.185000.json','["露零難辨蘂，月滿祇尋香。", "不受丹青涴，仍當雲水鄉。", "詩清見和靖，筆妙得高郎。", "當暑開霜素，蕭然六月凉。"]'),
('b115b642-b900-46c8-8bdf-7f39c633a812','放鷓鴣','陳宓','宋','宋诗','song-poetry','','[]','有生惟萬類，好惡與人參。',48,'全唐诗/poet.song.185000.json','["有生惟萬類，好惡與人參。", "以彼刳腸苦，爲吾悅口甘。", "蔬餐人所尚，肉食我誠慚。", "放汝飛翔去，騰雲更宿嵐。"]'),
('b30c811f-9ba6-4365-9157-5a7b7c9e25cb','南園','陳宓','宋','宋诗','song-poetry','','[]','水氣勝風凉，星輝當月光。',24,'全唐诗/poet.song.185000.json','["水氣勝風凉，星輝當月光。", "漁舟在何處，欵乃一聲長。"]'),
('7179948a-cbde-4475-8108-fcc6ce79d6ea','和王丞邁  其一','陳宓','宋','宋诗','song-poetry','','[]','宰縣殊無補，初心復負書。',48,'全唐诗/poet.song.185000.json','["宰縣殊無補，初心復負書。", "極知通一藝，苦恨乏三徐。", "立志期乾健，流年嘆月諸。", "已拚雙鬢白，未必古人如。"]'),
('89c83faf-c6de-4a8b-92e4-a7a049862e0a','和王丞邁  其二','陳宓','宋','宋诗','song-poetry','','[]','蚤慕登門寵，今欣後乘陪。',48,'全唐诗/poet.song.185000.json','["蚤慕登門寵，今欣後乘陪。", "窮山逢歲晚，佳節看陽來。", "地煖猶聞桂，冬深未見梅。", "高齋公事少，暇日足徘徊。"]'),
('78ce5d7f-ef7f-4f7f-9f58-16f29abf1679','觀鳳池橋上樑','陳宓','宋','宋诗','song-poetry','','[]','溪自清如鏡，官那束似羈。',48,'全唐诗/poet.song.185000.json','["溪自清如鏡，官那束似羈。", "不因乘小舫，還得賦新詩。", "邑肇千家聚，梁成萬世基。", "令慚無小補，刻石欲何詞。"]'),
('264caa1f-2ecf-406d-8262-f48161149b4d','題喻景山大飛書房','陳宓','宋','宋诗','song-poetry','','[]','仙谿七十里，半世祇聞名。',48,'全唐诗/poet.song.185000.json','["仙谿七十里，半世祇聞名。", "一日見山色，千年懷友情。", "古匏浮美醁，清水照塵纓。", "霜月亭亭白，連床語到明。"]'),
('b978d078-3fd4-44eb-a701-91e6c52bd7f1','庚午宴新舉人','陳宓','宋','宋诗','song-poetry','','[]','捧檄自來南，金門喜綴驂。',48,'全唐诗/poet.song.185000.json','["捧檄自來南，金門喜綴驂。", "一時驚得五，四季早魁三。", "摛藻皆人傑，吹竽祇自慚。", "功名期不朽，溪水碧於藍。"]'),
('208d832f-272c-4233-9a9f-42a42437c324','次柯東海於安溪流惠亭','陳宓','宋','宋诗','song-poetry','','[]','少壯成何事，蹉跎鬢欲翁。',48,'全唐诗/poet.song.185000.json','["少壯成何事，蹉跎鬢欲翁。", "尚餘朱墨日，可欠芰荷風。", "歸鷺依山白，新蟾蘸酒紅。", "晴空無點翳，秋氣遥梧桐。"]'),
('255ddc85-c538-4cfc-bd94-e3483a615975','往行都至嚴州烏駐館阻水留二日','陳宓','宋','宋诗','song-poetry','','[]','村館通宵冷，江鄉五月秋。',48,'全唐诗/poet.song.185000.json','["村館通宵冷，江鄉五月秋。", "野梅酸味足，隴麥餌香浮。", "水滿迷行徑，瀾揚遏去舟。", "亨衢如可待，莫厭小淹留。"]'),
('9ba91b83-3cfc-496f-be5e-20f15a825cae','趙戶自任所抵烏駐用前韵見示和之','陳宓','宋','宋诗','song-poetry','','[]','自昔桐城別，于今兩閲秋。',48,'全唐诗/poet.song.185000.json','["自昔桐城別，于今兩閲秋。", "暌違嗟地遠，聚散似萍浮。", "獨發皇都道，同登烏駐舟。", "人生非苟合，誰謂雨能留。"]'),
('63c3df6d-f53f-450d-8caa-c70d09eda5bf','近三衢阻雨  其一','陳宓','宋','宋诗','song-poetry','','[]','行李初逢雨，朝來猶望晴。',48,'全唐诗/poet.song.185000.json','["行李初逢雨，朝來猶望晴。", "霑濡端及月，慣習自忘情。", "密靄村村暝，流泉處處明。", "更餘三百里，江滿看舟行。"]'),
('2b9b9cc6-e50c-469d-a790-2ba93d05a1e9','近三衢阻雨  其二','陳宓','宋','宋诗','song-poetry','','[]','亭午還同曉，餘春祇見寒。',48,'全唐诗/poet.song.185000.json','["亭午還同曉，餘春祇見寒。", "不因陰雨窘，那識道途難。", "夾路峰巒隠，高田水潦漫。", "憑誰掃浮翳，杲杲出雲端。"]'),
('217f8dd9-a35a-4fbd-8fb3-df562aedab1f','題南康戲綵堂','陳宓','宋','宋诗','song-poetry','','[]','織女支機石，雲根幾許深。',48,'全唐诗/poet.song.185000.json','["織女支機石，雲根幾許深。", "月明偏得照，烟暝杳難尋。", "戲綵留奇跡，重題愧夙心。", "長年過半百，摹刻媿知音。"]'),
('1075836b-d2e1-4206-a879-8421c18fee41','紅藥','陳宓','宋','宋诗','song-poetry','','[]','山城風雨收，未省牡丹開。',24,'全唐诗/poet.song.185000.json','["山城風雨收，未省牡丹開。", "正訝遲紅藥，雙葩忽送來。"]'),
('cfd58bab-9cd0-46f9-ba72-97e8b068fa3a','次儲兄韵','陳宓','宋','宋诗','song-poetry','','[]','茗甌吹積雪，薰鼎撥寒灰。',48,'全唐诗/poet.song.185000.json','["茗甌吹積雪，薰鼎撥寒灰。", "覿面看脩竹，披襟映古槐。", "日長嗟侶少，風動喜朋來。", "共此林泉興，生涯水一杯。"]'),
('b78d1195-bfe5-4eb3-8e76-8bd47afa7fd7','掬水錫壺','陳宓','宋','宋诗','song-poetry','','[]','昔在延平郡，泉聲日夜聞。',48,'全唐诗/poet.song.185000.json','["昔在延平郡，泉聲日夜聞。", "六年歸故里，一縷憶晴雲。", "儋石終宵足，瓶罍竟日分。", "山中有飛瀑，未必愜朝曛。"]'),
('fa30a18d-a7db-4653-8af3-21ecf80e7260','題延平劍歸閣','陳宓','宋','宋诗','song-poetry','','[]','晉代難爲用，翻藏此水涯。',48,'全唐诗/poet.song.185000.json','["晉代難爲用，翻藏此水涯。", "在天猶有赫，鎮地永無邪。", "雨過疑留迹，風飛去莫遮。", "誰云寒瀨底，折戟伴沈沙。"]'),
('746eb318-5ff4-4eda-a7b2-58aa3733c182','次樓宗簿禱雨韵  其一','陳宓','宋','宋诗','song-poetry','','[]','君侯憂國念，食頃詎能忘。',48,'全唐诗/poet.song.185000.json','["君侯憂國念，食頃詎能忘。", "盡變庖厨饌，全銷燕寢香。", "連朝成靄靄，中夜忽浪浪。", "坐想溪十曲，恩波似個長。"]'),
('c3ab5507-0637-40f9-9995-d85306c870a5','次樓宗簿禱雨韵  其二','陳宓','宋','宋诗','song-poetry','','[]','旱氣滿南州，深貽旰食憂。',48,'全唐诗/poet.song.185000.json','["旱氣滿南州，深貽旰食憂。", "蟹能升古井，龍敢卧深湫。", "德政真無愧，豐年信可求。", "野人無別慕，鼓腹事西疇。"]'),
('621b57ca-9d9a-4028-b73f-c9e642d99f0f','重九與劉學錄','陳宓','宋','宋诗','song-poetry','','[]','休暇常難值，招邀愧已頻。',48,'全唐诗/poet.song.185000.json','["休暇常難值，招邀愧已頻。", "暫辭霜際菊，終作雨來人。", "適意能迂訪，秋芳正錯陳。", "桂蘭供俯仰，况有拒霜新。"]'),
('e0923a56-cd03-4dfa-8a6e-7735b4fcf470','謝蔡知縣白蓮栽','陳宓','宋','宋诗','song-poetry','','[]','忠惠當年種，濂溪此日分。',48,'全唐诗/poet.song.185000.json','["忠惠當年種，濂溪此日分。", "開筵勝玉碗，圍坐當冰盆。", "性地元無染，心源自有根。", "江湖情漸懶，樂在閉柴門。"]'),
('784c7966-ac35-4db1-88c6-00e031417617','送趙糾之潮州任','陳宓','宋','宋诗','song-poetry','','[]','昔佐仙遊縣，聲稱已勝喧。',48,'全唐诗/poet.song.185000.json','["昔佐仙遊縣，聲稱已勝喧。", "幾年加問學，名郡事平反。", "犴獄情難察，鰥嫠志勇冤。", "惟將明與謹，用表贈行言。"]'),
('b65b3f0e-2b43-427c-8f0f-d7307516f247','觀瀑布柬同遊諸友','陳宓','宋','宋诗','song-poetry','','[]','兩瀑五十里，炎蒸雨雪霶。',24,'全唐诗/poet.song.185000.json','["兩瀑五十里，炎蒸雨雪霶。", "那知廬阜境，元只在吾鄉。"]'),
('4536944c-c07a-4a29-9465-3102ec9a66d2','往瀨溪西重山觀瀑分韵得還字','陳宓','宋','宋诗','song-poetry','','[]','來自崑崙派，全勝廬岳山。',48,'全唐诗/poet.song.185000.json','["來自崑崙派，全勝廬岳山。", "樁雲何日息，注海幾時還。", "翠碧倚鋒鍔，青冥振佩環。", "主人專一壑，那得鬢毛斑。"]'),
('57f165af-2a68-42db-953d-bf69bdf0cbd6','喻景山索詩用石間韵','陳宓','宋','宋诗','song-poetry','','[]','交遊二十載，恐負壁間名。',48,'全唐诗/poet.song.185000.json','["交遊二十載，恐負壁間名。", "圖籍有真味，林泉無俗情。", "我方穿短履，君始彯長纓。", "出處今殊致，同懷山月明。"]'),
('eace46ee-0a03-4403-a4bc-b7c6ee021766','次潘丈韵與劉學錄','陳宓','宋','宋诗','song-poetry','','[]','以彼月中桂，來娛地上仙。',48,'全唐诗/poet.song.185000.json','["以彼月中桂，來娛地上仙。", "沖融胸內樂，擺落世間緣。", "人語春風裏，秋歸夕照邊。", "主翁長靜坐，不是學安然。"]'),
('b36b8384-aabf-491e-b889-54212f666299','十月菊','陳宓','宋','宋诗','song-poetry','','[]','白玉三千界，黄金百萬錢。',48,'全唐诗/poet.song.185000.json','["白玉三千界，黄金百萬錢。", "雖遲九日後，却戰一陽前。", "不願遊人看，仍疎酒盞邊。", "天公豈無意，垂老更芳妍。"]'),
('8fea4d25-3e2a-4ae0-a587-8e6dd77a3af7','有贈鹿忽生麛承劉學錄惠詩以韵謝之','陳宓','宋','宋诗','song-poetry','','[]','麀鹿方辭贈，秋來忽有麛。',48,'全唐诗/poet.song.185000.json','["麀鹿方辭贈，秋來忽有麛。", "暫能娛市隠，終遣傍雲栖。", "幽事漁樵詫，佳篇李杜齊。", "行看雙挺角，未羨駭群雞。"]'),
('fc727bee-4159-4737-88ae-3119685a2bd6','贈林尹仲','陳宓','宋','宋诗','song-poetry','','[]','八年前會晤，猶憶刺桐鄉。',48,'全唐诗/poet.song.185000.json','["八年前會晤，猶憶刺桐鄉。", "君眼雖非白，吾顔已過蒼。", "有求皆妄想，無欲是良方。", "不學神仙術，他時共一觴。"]'),
('82a0a797-e0be-42d5-b372-3d77e3ef4339','安溪勸農詩 勸孝養','陳宓','宋','宋诗','song-poetry','','[]','父母辛勤養汝身，直須五鼎奉雙親。',32,'全唐诗/poet.song.185000.json','["父母辛勤養汝身，直須五鼎奉雙親。", "有田若不勤耕稼，菽水猶虧豈是人。"]'),
('3370a46d-ab8e-42bc-9991-e9f54d567af8','安溪勸農詩 勸耘苗','陳宓','宋','宋诗','song-poetry','','[]','力勤瘠地亦良田，豐歉由人莫問天。',32,'全唐诗/poet.song.185000.json','["力勤瘠地亦良田，豐歉由人莫問天。", "曝背耘苗能著力，天公畢竟也相憐。"]'),
('23e6ffce-0e16-4214-b3be-222a93d27871','安溪勸農詩 勸耕荒田','陳宓','宋','宋诗','song-poetry','','[]','七閩寸土直錢多，况是泉山價倍高。',32,'全唐诗/poet.song.185000.json','["七閩寸土直錢多，况是泉山價倍高。", "怪爾小民無別業，如何荒畝長蓬蒿。"]'),
('f07cc7b3-6d3d-4445-af17-023019b62a63','安溪勸農詩 勸種植','陳宓','宋','宋诗','song-poetry','','[]','是處荒山欲接天，土膏如麵草如氈。',32,'全唐诗/poet.song.185000.json','["是處荒山欲接天，土膏如麵草如氈。", "及時便種松杉子，遠計收功只十年。"]'),
('107baa78-37c9-4710-a107-610c14d3ef8d','安溪勸農詩 勸息訟','陳宓','宋','宋诗','song-poetry','','[]','田夫所入最爲艱，終歲辛勤不得閑。',32,'全唐诗/poet.song.185000.json','["田夫所入最爲艱，終歲辛勤不得閑。", "勸爾小爭須隠忍，破家只在片時間。"]'),
('ffdc4505-e3cf-4704-bddb-756fc9ccaece','安溪勸農詩 勸貧富相資 其一','陳宓','宋','宋诗','song-poetry','','[]','舉債當知濟汝窮，取錢須念利難供。',32,'全唐诗/poet.song.185000.json','["舉債當知濟汝窮，取錢須念利難供。", "富人心要憐貧者，貧者身全仰富翁。"]'),
('0cef6e56-b7c0-4f4f-afb1-2208564f0d4e','安溪勸農詩 勸貧富相資 其二','陳宓','宋','宋诗','song-poetry','','[]','汗顔爲令已三年，二稅無因放汝錢。',32,'全唐诗/poet.song.185000.json','["汗顔爲令已三年，二稅無因放汝錢。", "但願人人知務本，他時莫忘勸農篇。"]'),
('3c119842-7a6a-48d5-96eb-0a3de6ce4067','題安溪流惠亭','陳宓','宋','宋诗','song-poetry','','[]','平蕪幾載翳雲烟，一日重開便豁然。',64,'全唐诗/poet.song.185000.json','["平蕪幾載翳雲烟，一日重開便豁然。", "須信耕桑皆帝力，謾將翔泳祝堯年。", "金堤新插千株柳，玉井仍看十丈蓮。", "縣令欲同民快樂，西風來看遶湖田。"]'),
('b260cb24-08f5-411a-9aec-b9b7e2aa664a','題安溪雙清閣','陳宓','宋','宋诗','song-poetry','','[]','重開傑閣似天成，氣壓塵闤境自清。',64,'全唐诗/poet.song.185000.json','["重開傑閣似天成，氣壓塵闤境自清。", "一水深澄蒼玉遠，五峰齊峙翠屏橫。", "未諧廣厦萬間志，且愜行人六月情。", "蚤晚定能誇盛事，鳳池橋上看蓬瀛。"]'),
('2bf008b3-15e4-49ae-a355-a2b6e6cbfc20','登安溪蓬萊山謝雨','陳宓','宋','宋诗','song-poetry','','[]','我來兩月值冬晴，多謝靈明答寸誠。',32,'全唐诗/poet.song.185000.json','["我來兩月值冬晴，多謝靈明答寸誠。", "一瓣凈香猶未染，留得瓊英蓋短垣。"]'),
('ceb3dad6-b658-477a-aa10-df6671a97e07','贈梁運屬','陳宓','宋','宋诗','song-poetry','','[]','萱堂處處盡陽春，二月嚴霜凜獨陳。',64,'全唐诗/poet.song.185000.json','["萱堂處處盡陽春，二月嚴霜凜獨陳。", "六載侍旁勤奉養，五年居外備艱屯。", "嗟君不愧曾參孝，愧我殊無考叔純。", "齊與楚咻雖衆勝，會看至行感蒼旻。"]'),
('e7550e84-4806-4d42-b3f0-19582fdd9fc0','官松','陳宓','宋','宋诗','song-poetry','','[]','團團翠蓋中圓規，風雨精神壯兩儀。',64,'全唐诗/poet.song.185000.json','["團團翠蓋中圓規，風雨精神壯兩儀。", "一日不戕凌雪操，千年留得入雲枝。", "長垂道路清涼蔭，更有神仙灑落姿。", "南國至今忠恵澤，往來那更誦坡詩。"]'),
('9e07b2ee-4648-417f-b571-1887e7b8d241','暮春','陳宓','宋','宋诗','song-poetry','','[]','蘭亭明日禊餘春，風冷難回積雨雲。',32,'全唐诗/poet.song.185000.json','["蘭亭明日禊餘春，風冷難回積雨雲。", "不惜芳菲倦遊賞，雅宜竹下閉門人。"]'),
('be904f71-4723-4eea-bdbb-8fbcf05e5805','小園送春','陳宓','宋','宋诗','song-poetry','','[]','一春强半尚無晴，有負淵明日涉名。',64,'全唐诗/poet.song.185000.json','["一春强半尚無晴，有負淵明日涉名。", "鶑粟已粧紅葉艷，青梅尚覺荔枝生。", "可憐蜂蝶攀轅意，尚欲羲和反旆行。", "桃李不言流水畔，遊人到此自多情。"]');
